(window.courseContent = window.courseContent || {})["000013"] = {"files/Хирургически болести/Гръдна хирургия/0-msg-Колоквиум.html":"<!DOCTYPE html>\n<html lang=\"bg\">\n<head>\n  <meta charset=\"UTF-8\">\n  <meta name=\"viewport\" content=\"width=device-width, initial-scale=1.0\">\n  <title>Колоквиум</title>\n  <link rel=\"stylesheet\" href=\"https://cdn.jsdelivr.net/npm/katex@0.16.4/dist/katex.min.css\">\n  <style>\n    body {\n      font-family: \"Open Sans\", Arial, sans-serif;\n      max-width: 1550px;\n      margin: 0.5rem auto;\n      padding: 0 1rem;\n      line-height: 1.6;\n      color: #1f2937;\n    }\n    h1, h2, h3, h4 {\n      font-weight: 600;\n      margin-top: 0.7em;\n      margin-bottom: 0;\n      color: #588157;\n    }\n    h1 { font-size: 1.65em; }\n    h2 { font-size: 1.3em; }\n    h3 { font-size: 1.1em; margin-bottom: 0; }\n    h4 { font-size: 1.05em; margin-bottom: 0; }\n    h1 + h2, h1 + h3, h1 + h4, h2 + h3, h2 + h4, h3 + h4 { margin-top: 0.1em; }\n    p {\n      margin: 0.3em 0;\n      white-space: pre-wrap;\n    }\n    hr {\n      margin: 0.45em 0 0.2em;\n    }\n    hr + h1,\n    hr + h2,\n    hr + h3,\n    hr + h4 {\n      margin-top: 0.2em;\n    }\n    hr + p,\n    hr + ul,\n    hr + ol,\n    hr + blockquote,\n    hr + pre,\n    hr + table {\n      margin-top: 0.08em;\n    }\n    p + ul, p + ol { margin-top: 0.2em; }\n    h1 + p, h2 + p, h3 + p, h4 + p,\n    h1 + ul, h2 + ul, h3 + ul, h4 + ul,\n    h1 + ol, h2 + ol, h3 + ol, h4 + ol {\n      margin-top: 0;\n    }\n    ul, ol {\n      margin: 0.2em 0;\n      padding-left: 1.5em;\n      list-style-position: outside;\n    }\n    li { margin: 0.2em 0; }\n    li p {\n      margin: 0;\n      padding: 0;\n      display: inline;\n    }\n    li > ul, li > ol {\n      margin: 0.15em 0 0 0;\n      padding-left: 1.5em;\n    }\n    ul ul, ul ol, ol ul, ol ol {\n      margin-top: 0.1em;\n      padding-left: 1.5em;\n    }\n    ul ul { list-style-type: circle; }\n    ul ul ul { list-style-type: square; }\n    strong { font-weight: 600; }\n    em { font-style: italic; }\n    code {\n      background: rgba(218, 215, 205, 0.3);\n      padding: 2px 6px;\n      border-radius: 3px;\n      font-family: \"Courier New\", monospace;\n      font-size: 0.9em;\n    }\n    pre {\n      background: rgba(255, 255, 255, 0.5);\n      padding: 12px;\n      border-radius: 4px;\n      overflow-x: auto;\n      margin: 0.5em 0;\n      font-family: \"Courier New\", monospace;\n    }\n    pre code {\n      background: none;\n      padding: 0;\n    }\n    blockquote {\n      border-left: 3px solid #588157;\n      padding-left: 1em;\n      margin: 0.5em 0;\n      font-style: italic;\n      color: #166534;\n    }\n    table {\n      border-collapse: collapse;\n      margin: 0.75em 0;\n      width: 100%;\n      table-layout: auto;\n    }\n    th, td {\n      border: 1px solid rgba(2, 2, 2, 0.2);\n      padding: 6px 10px;\n      text-align: left;\n      vertical-align: top;\n      height: 24px;\n      line-height: 1.2;\n    }\n    thead th {\n      background: rgba(88, 129, 87, 0.13);\n      font-weight: 600;\n    }\n    tbody tr:nth-child(odd) {\n      background: rgba(88, 129, 87, 0.06);\n    }\n    /* Image alignment rules for exported content and md-viewer */\n    img[data-align=\"left\"] {\n      display: block;\n      margin: 8px auto 8px 0;\n    }\n    img[data-align=\"center\"] {\n      display: block;\n      margin: 8px auto;\n    }\n    img[data-align=\"right\"] {\n      display: block;\n      margin: 8px 0 8px auto;\n    }\n    .audio-link-inline {\n      display: inline-flex;\n      align-items: center;\n      gap: 8px;\n      margin: 0.2em 0;\n      max-width: 100%;\n      vertical-align: middle;\n    }\n    .audio-link-icon {\n      width: 28px;\n      height: 28px;\n      border: 1px solid #588157;\n      border-radius: 999px;\n      background: #f0f7f0;\n      color: #2f5d50;\n      cursor: pointer;\n      font-size: 14px;\n      line-height: 1;\n      display: inline-flex;\n      align-items: center;\n      justify-content: center;\n      flex: 0 0 auto;\n    }\n    .audio-link-inline audio {\n      position: absolute;\n      width: 1px;\n      height: 1px;\n      opacity: 0;\n      overflow: hidden;\n      pointer-events: none;\n    }\n    .audio-link-icon img {\n      width: 14px;\n      height: 14px;\n      object-fit: contain;\n      pointer-events: none;\n    }\n    a {\n      color: inherit; /* Changed to inherit */\n      text-decoration: underline;\n    }\n    a:hover {\n      color: #74b673;\n    }\n    /* Keep <p> tags inside list items on same line (as they appear in editor) */\n    li p {\n      margin: 0 !important;\n      padding: 0 !important;\n      display: inline !important;\n    }\n    /* Prevent nested list paragraph issues */\n    li > ul,\n    li > ol {\n      margin: 0.15em 0 0 0;\n      padding-left: 1.5em;\n    }\n    /* Ensure list structure is clean */\n    ul ul, ul ol,\n    ol ul, ol ol {\n      margin-top: 0.1em;\n      padding-left: 1.5em;\n    }\n    @media (max-width: 768px) {\n      body {\n        margin: 0.5rem 0;\n        padding: 0 0.5rem;\n        font-size: 16px;\n      }\n      h1 { font-size: 1.65em; }\n      h2 { font-size: 1.3em; }\n      h3 { font-size: 1.1em; }\n      p { margin: 0.3em 0; }\n      ul, ol { padding-left: 1.5em; }\n      li { margin: 0.2em 0; }\n      table { font-size: 0.9em; }\n      th, td { padding: 6px 10px; }\n    }\n    .editor-note {\n      text-decoration: underline dotted #a3b18a;\n      text-decoration-thickness: 2px;\n      text-underline-offset: 2px;\n      text-decoration-skip-ink: none;\n      cursor: help;\n      position: relative;\n    }\n    .note-tooltip {\n      display: none;\n      position: absolute;\n      background-color: #f0f7f0;\n      color: #1f2937;\n      border: 1px solid #588157;\n      border-radius: 4px;\n      padding: 8px 12px;\n      width: fit-content;\n      max-width: min(700px, calc(100vw - 20px));\n      max-height: calc(100vh - 20px);\n      overflow: auto;\n      box-sizing: border-box;\n      box-shadow: 0 2px 8px rgba(0,0,0,0.2);\n      z-index: 10000;\n      font-size: 0.9em;\n      line-height: 1.4;\n      word-wrap: break-word;\n    }\n    .note-tooltip ul, .note-tooltip ol {\n      margin: 0 !important;\n      padding-left: 20px !important;\n    }\n    .note-tooltip li {\n      margin: 0 0 0.1em 0 !important;\n      padding: 0 !important;\n      line-height: 1.2 !important;\n    }\n    .note-tooltip li:last-child {\n      margin-bottom: 0 !important;\n    }\n    .note-tooltip .note-table-scroll {\n      overflow-x: hidden;\n      margin: 0.3em 0;\n      max-width: 100%;\n    }\n    .note-tooltip table {\n      border-collapse: collapse;\n      width: 100%;\n      max-width: 100%;\n      min-width: 0;\n      table-layout: fixed;\n      background: #ffffff;\n    }\n    .note-tooltip th,\n    .note-tooltip td {\n      border: 1px solid rgba(88, 129, 87, 0.35);\n      padding: 4px 8px;\n      text-align: left;\n      vertical-align: top;\n      line-height: 1.3;\n      white-space: normal;\n      overflow-wrap: anywhere;\n      word-break: break-word;\n    }\n    .note-tooltip thead th {\n      background: rgba(88, 129, 87, 0.12);\n      font-weight: 600;\n    }\n  </style>\n  <script>\n    document.addEventListener('DOMContentLoaded', function() {\n      const tooltip = document.createElement('div');\n      tooltip.className = 'note-tooltip';\n      document.body.appendChild(tooltip);\n\n      function parseNoteMarkdown(text) {\n        if (!text) return '';\n\n        const splitTableCells = function(line) {\n          return String(line || '')\n            .trim()\n            .replace(/^\\|/, '')\n            .replace(/\\|$/, '')\n            .split('|')\n            .map(function(cell) { return cell.trim(); });\n        };\n\n        const isTableSeparatorLine = function(line) {\n          const cells = splitTableCells(line);\n          return cells.length > 0 && cells.every(function(cell) {\n            return /^:?-{3,}:?$/.test(cell);\n          });\n        };\n\n        const getTableAlignment = function(cell) {\n          if (/^:-{3,}:$/.test(cell)) return 'center';\n          if (/^-{3,}:$/.test(cell)) return 'right';\n          if (/^:-{3,}$/.test(cell)) return 'left';\n          return '';\n        };\n\n        let lines = text.split('\\n');\n        let html = [];\n        let stack = [];\n\n        for (let i = 0; i < lines.length; i++) {\n          let line = lines[i];\n\n          let indentMatch = line.match(/^(\\s*)/);\n          let indent = indentMatch ? indentMatch[1].length : 0;\n          let content = line.trim();\n\n          const nextLine = i + 1 < lines.length ? lines[i + 1].trim() : '';\n          const maybeTableHeader = content.includes('|') && splitTableCells(content).length >= 2;\n          const maybeTableSeparator = nextLine.includes('|') && isTableSeparatorLine(nextLine);\n\n          if (maybeTableHeader && maybeTableSeparator) {\n            while (stack.length > 0) {\n              let closed = stack.pop();\n              html.push('</' + closed.type + '>');\n            }\n\n            const headerCells = splitTableCells(content);\n            const alignCells = splitTableCells(nextLine);\n\n            html.push('<div class=\"note-table-scroll\"><table><thead><tr>');\n            headerCells.forEach(function(cell, idx) {\n              const align = getTableAlignment(alignCells[idx] || '');\n              const alignAttr = align ? ' style=\"text-align:' + align + ';\"' : '';\n              html.push('<th' + alignAttr + '>' + cell + '</th>');\n            });\n            html.push('</tr></thead><tbody>');\n\n            i += 2;\n            while (i < lines.length) {\n              const rowLine = lines[i].trim();\n              if (!rowLine || !rowLine.includes('|')) break;\n              if (isTableSeparatorLine(rowLine)) {\n                i++;\n                continue;\n              }\n\n              const rowCells = splitTableCells(rowLine);\n              if (rowCells.length === 0) {\n                i++;\n                continue;\n              }\n\n              html.push('<tr>');\n              rowCells.forEach(function(cell, idx) {\n                const align = getTableAlignment(alignCells[idx] || '');\n                const alignAttr = align ? ' style=\"text-align:' + align + ';\"' : '';\n                html.push('<td' + alignAttr + '>' + cell + '</td>');\n              });\n              html.push('</tr>');\n              i++;\n            }\n\n            html.push('</tbody></table></div>');\n            i--;\n            continue;\n          }\n\n          let isUl = /^[-*]\\s+(.+)/.test(content);\n          let isOl = /^\\d+\\.\\s+(.+)/.test(content);\n\n          if (isUl || isOl) {\n            let listType = isUl ? 'ul' : 'ol';\n            let match = isUl ? content.match(/^[-*]\\s+(.+)/) : content.match(/^\\d+\\.\\s+(.+)/);\n            let itemText = match[1];\n\n            if (stack.length === 0) {\n              stack.push({ type: listType, indent: indent });\n              html.push('<' + listType + '>');\n            } else {\n              let last = stack[stack.length - 1];\n\n              if (indent > last.indent) {\n                stack.push({ type: listType, indent: indent });\n                html.push('<' + listType + '>');\n              } else if (indent < last.indent) {\n                while (stack.length > 0 && stack[stack.length - 1].indent > indent) {\n                  let closed = stack.pop();\n                  html.push('</' + closed.type + '>');\n                }\n                if (stack.length === 0 || stack[stack.length - 1].indent !== indent) {\n                   stack.push({ type: listType, indent: indent });\n                   html.push('<' + listType + '>');\n                } else if (stack[stack.length - 1].type !== listType) {\n                   let closed = stack.pop();\n                   html.push('</' + closed.type + '>');\n                   stack.push({ type: listType, indent: indent });\n                   html.push('<' + listType + '>');\n                }\n              } else {\n                if (last.type !== listType) {\n                  let closed = stack.pop();\n                  html.push('</' + closed.type + '>');\n                  stack.push({ type: listType, indent: indent });\n                  html.push('<' + listType + '>');\n                }\n              }\n            }\n            html.push('<li>' + itemText + '</li>');\n          } else {\n            if (content !== '') {\n               while (stack.length > 0) {\n                 let closed = stack.pop();\n                 html.push('</' + closed.type + '>');\n               }\n            }\n            if (/^(?:---|\\*\\*\\*|___)$/.test(content)) {\n              html.push('<hr>');\n            } else if (/^#{1,4}\\s+/.test(content)) {\n              const headingMatch = content.match(/^(#{1,4})\\s+(.+)$/);\n              if (headingMatch) {\n                const level = headingMatch[1].length;\n                html.push('<h' + level + '>' + headingMatch[2] + '</h' + level + '>');\n              }\n            } else if (content) {\n              html.push(content + '<br>');\n            } else {\n              html.push('<br>');\n            }\n          }\n        }\n\n        while (stack.length > 0) {\n          let closed = stack.pop();\n          html.push('</' + closed.type + '>');\n        }\n\n        let result = html.join('')\n          .replace(/!\\[(.*?)\\]\\((.*?)\\)/g, '<img src=\"$2\" alt=\"$1\">')\n          .replace(/\\*\\*(.+?)\\*\\*/g, '<strong>$1</strong>')\n          .replace(/__(.+?)__/g, '<strong>$1</strong>')\n          .replace(/\\*(.+?)\\*/g, '<em>$1</em>')\n          .replace(/_(.+?)_/g, '<em>$1</em>')\n          .replace(/`(.+?)`/g, '<code>$1</code>')\n          .replace(/\\[(.+?)\\]\\((.+?)\\)/g, '<a href=\"$2\" target=\"_blank\">$1</a>');\n\n        result = result\n          .replace(/<br><ul>/g, '<ul>')\n          .replace(/<br><ol>/g, '<ol>')\n          .replace(/</ul><br>/g, '</ul>')\n          .replace(/</ol><br>/g, '</ol>');\n\n        return result;\n      }\n\n      document.body.addEventListener('mouseover', function(e) {\n        if (e.target.classList.contains('editor-note')) {\n          const note = e.target.dataset.note;\n          if (note) {\n            tooltip.innerHTML = parseNoteMarkdown(note);\n            tooltip.style.display = 'block';\n            const rect = e.target.getBoundingClientRect();\n            const tooltipRect = tooltip.getBoundingClientRect();\n            const pageX = window.scrollX || window.pageXOffset;\n            const pageY = window.scrollY || window.pageYOffset;\n            const maxLeft = pageX + window.innerWidth - tooltipRect.width - 10;\n            const minLeft = pageX + 10;\n\n            let left = rect.left + pageX;\n            if (left > maxLeft) left = maxLeft;\n            if (left < minLeft) left = minLeft;\n\n            let top = rect.bottom + pageY + 6;\n            const maxTop = pageY + window.innerHeight - tooltipRect.height - 10;\n            if (top > maxTop) {\n              top = rect.top + pageY - tooltipRect.height - 6;\n            }\n            if (top < pageY + 10) top = pageY + 10;\n\n            tooltip.style.left = left + 'px';\n            tooltip.style.top = top + 'px';\n          }\n        }\n      });\n\n      document.body.addEventListener('mouseout', function(e) {\n        if (e.target.classList.contains('editor-note')) {\n          setTimeout(() => {\n            if (!tooltip.matches(':hover')) {\n              tooltip.style.display = 'none';\n            }\n          }, 100);\n        }\n      });\n\n      tooltip.addEventListener('mouseleave', function() {\n        tooltip.style.display = 'none';\n      });\n    });\n  </script>\n</head>\n<body>\n<p style=\"text-align: left\"></p><h1 style=\"text-align: center\">Колоквиум по гръдна хирургия</h1><p><strong>При аспирация белодробен абсцес се развива най-често в:</strong></p><ul><li><strong><span style=\"color: rgb(255, 0, 0)\">Задните сегменти на среден и долен лоб</span></strong></li><li>Среден лоб</li><li>Горните сегменти</li></ul><p><strong>Индикации за хирургично лечение при остър абсцес са:</strong></p><ul><li><strong><span style=\"color: rgb(255, 0, 0)\">Обилно кървене</span></strong></li><li>Силна кашлица</li><li>Висок фебрилитет</li></ul><p><strong>Кои белодробни абсцеси наричаме “закрити”?</strong></p><ul><li><strong><span style=\"color: rgb(255, 0, 0)\">Абсцесите без пробив в бронх</span></strong></li><li>Централните абсцеси</li><li>Периферните абсцеси</li><li>Няма верен отговор</li></ul><p><strong>Аспирационните абсцеси на белия дроб се характеризират със сегментарен характер на пораженията.</strong></p><ul><li><span style=\"color: rgb(255, 0, 0)\"><strong>False</strong></span></li><li>True</li></ul><p><strong>Хирургично лечение при дребноклетъчен белодробен карцином:</strong></p><ul><li><strong><span style=\"color: rgb(255, 0, 0)\">Прилага се само при определени индикации</span></strong></li><li>Прилага се при всички болни</li></ul><p><strong>Причина за поява на венозен застой в областта на главата, шията, гръдния кош и горни крайници при пациенти с централен карцином на десен бял дроб е:</strong></p><ul><li><strong><span style=\"color: rgb(255, 0, 0)\">Притискане на v. cava sup.</span></strong></li><li>Притискане на a. pulmonalis dextra.</li><li>Прорастване във v. azygos.</li></ul><p><strong>Ако при рентгенография сме установили хиповентилация на сегмент, лоб или цял бял дроб, на първо място трябва да изключим като възможна причина:</strong></p><ul><li><strong><span style=\"color: rgb(255, 0, 0)\">Карцином на белия дроб</span></strong></li><li>Паразитарна киста на белия дроб</li><li>Белодробен емфизем</li><li>Чуждо тяло</li><li>Доброкачествен тумор</li></ul><p><strong>При TNM класификацията T-критерият характеризира:</strong></p><ul><li><strong>Туморът</strong></li><li>Далечните метастази</li><li>Лимфните възли</li></ul><p><strong>При пациент, претърпял ПТП с воланна травма ще изследваме:</strong></p><ul><li><strong><span style=\"color: rgb(255, 0, 0)\">Всички отговори са верни</span></strong></li><li>ЕКГ</li><li>ПКК, биохимия</li><li>Коагулация</li><li>Сърдечни ензими</li></ul><hr contenteditable=\"false\" data-editor-void=\"true\" tabindex=\"-1\"><p><strong>Гръдната травма се разделя на закрита и открита.</strong></p><ul><li><strong><span style=\"color: rgb(255, 0, 0)\">True</span></strong></li><li>False</li></ul><p><strong>При травматичен напрегнат пневмоторакс в стационарни условия хирургичната тактика е:</strong></p><ul><li><strong><span style=\"color: rgb(255, 0, 0)\">Плеврален дренаж</span></strong></li><li>Интубация и апаратно дишане</li><li>Интеркостална новокаинова блокада</li><li>Подаване на кислород назално</li></ul><p><strong>Най-честата причина за гръдна травма е:</strong></p><ul><li><strong><span style=\"color: rgb(255, 0, 0)\">ПТП</span></strong></li><li>Огнестрелна рана</li><li>Височинна травма</li></ul><p><strong>Характерен признак за лезия на белодробен паренхим при закрита гръдна травма е:</strong></p><ul><li><strong><span style=\"color: rgb(255, 0, 0)\">Кръвохрак</span></strong></li><li><strong><span style=\"color: rgb(255, 0, 0)\">Хемоторакс</span></strong></li><li><strong><span style=\"color: rgb(255, 0, 0)\">Дихателна недостатъчност</span></strong></li><li><strong><span style=\"color: rgb(255, 0, 0)\">Рентгенологично воалирана гръдна половина</span></strong></li></ul><p><strong>С помощта на сцинтиграфията на щитовидната жлеза НЕ може да се получи информация за:</strong></p><ul><li><strong><span style=\"color: rgb(255, 0, 0)\">Подвижност на жлезата</span></strong></li><li>Хиперфункция на жлезата</li><li>Наличие на “горещи възли”</li><li>Наличие на “студени възли”</li><li>Локализация на жлезата</li></ul><p><strong>Каква е причината за поява и развитие на тиреотоксикоза?</strong></p><ul><li><strong><span style=\"color: rgb(255, 0, 0)\">Автоимунна</span></strong></li><li>Алергична</li><li>Инфекциозна</li><li>Нервно-психична</li><li>Наследствена</li></ul><p><strong>Радиоактивен йод използваме за диагностика на туморни процеси на:</strong></p><ul><li><strong><span style=\"color: rgb(255, 0, 0)\">Щитовидната жлеза</span></strong></li><li>Панкреаса</li><li>Няма верен отговор</li><li>Паращитовидните жлези</li><li>Стомаха</li></ul><p><strong>Посочете ГРЕШНОТО твърдение! При хирургичното лечение на тиреотоксикоза могат да възникнат следните усложнения:</strong></p><ul><li><strong><span style=\"color: rgb(255, 0, 0)\">Увреждане на слуха и зрението</span></strong></li><li>Тиреотоксична криза</li><li>Кървене</li><li>Пареза на гласните връзки</li></ul><p><strong>Политейлия е:</strong></p><ul><li><strong><span style=\"color: rgb(255, 0, 0)\">Добавъчни мамили</span></strong></li><li>Едностранен секрет от млечната жлеза</li><li>Разлика в големината на двете млечни жлези</li><li>Добавъчни гърди</li></ul><p><strong>Далечни метастази при карцином на млечната жлеза най-често се наблюдават в:</strong></p><ul><li><strong><span style=\"color: rgb(255, 0, 0)\">Белия дроб</span></strong></li><li><strong><span style=\"color: rgb(255, 0, 0)\">Мозъка</span></strong></li><li><strong><span style=\"color: rgb(255, 0, 0)\">Костите</span></strong></li><li>Перитонеума</li></ul><p><strong>От изброените методи за изследване при диагностика на заболявания на млечната жлеза не се прилага:</strong></p><ul><li><strong><span style=\"color: rgb(255, 0, 0)\">Сцинтиграфия</span></strong></li><li>Ехоскопия</li><li>Мамография</li><li>Цитологично изследване на секрет от мамилата</li></ul><p><strong>На колко квадранта се разделя анатомично млечната жлеза:</strong></p><ul><li><strong><span style=\"color: rgb(255, 0, 0)\">5</span></strong></li><li>4</li><li>3</li><li>6</li></ul><p><strong>Рентгенографията при спонтанен пневмоторакс се прави:</strong></p><ul><li><strong><span style=\"color: rgb(255, 0, 0)\">В инспириум</span></strong></li><li>В експириум</li><li>Няма значение</li></ul><p><strong>Основен метод при лечението на острия емпием на плеврата е:</strong></p><ul><li><strong><span style=\"color: rgb(255, 0, 0)\">Плеврален дренаж + лаваж на плевралната кухина + антибиотична терапия</span></strong></li><li>Интраплеврална инстилация на антибиотик</li><li>Обща антибактериална терапия</li><li>Плеврални пункции</li></ul><p><strong>Рентгенологичната характеристика на пио-пневмоторакса е:</strong></p><ul><li><strong><span style=\"color: rgb(255, 0, 0)\">Сянка с хоризонтална ниво</span></strong></li><li>Нарастваща по интензивност сянка с неясни граници</li><li>Неравномерно петнисто засенчване на плевралната половина</li><li>Равномерно затъмнение на белодробното поле</li><li>Изместване на средостението към здравата страна</li></ul><p><strong>Хирургичното лечение на пио-пневмоторакс започва с:</strong></p><ul><li><strong><span style=\"color: rgb(255, 0, 0)\">Дренаж и лаваж на плевралната кухина</span></strong></li><li>Противовъзпалителна терапия</li><li>Плеврални пункции</li><li>Интеркостална спирт-лидокаинова блокада</li><li>Торакотомия</li></ul><p><strong>Коя е основната опасност при хроничен емпием на плеврата?</strong></p><ul><li><strong><span style=\"color: rgb(255, 0, 0)\">Персистиране на инфекциозното огнище и развитие на амилоидоза на вътрешните органи</span></strong></li><li>Гнойна интоксикация</li><li>Полиорганна недостатъчност на базата на интоксикация</li><li>Развитие на белодробна гангрена</li><li>Хронична белодробна недостатъчност</li></ul><p><strong>Съчетаната ехинококоза е:</strong></p><ul><li><strong><span style=\"color: rgb(255, 0, 0)\">Полиорганна</span></strong></li><li>Едностранна и двустранна</li><li>Засягане на двата бели дроба</li><li>Повторно заразяване</li></ul><p><strong>На консервативно лечение подлежат:</strong></p><ul><li><strong><span style=\"color: rgb(255, 0, 0)\">Всички изброени</span></strong></li><li><strong><span style=\"color: rgb(255, 0, 0)\">Полиорганна авансирала ехинококоза</span></strong></li><li><strong><span style=\"color: rgb(255, 0, 0)\">Малки единични кисти до 3–4 см</span></strong></li><li><strong><span style=\"color: rgb(255, 0, 0)\">Неоперабилни болни</span></strong></li></ul><p><strong>Хидро–пневмотораксът като усложнение на белодробната ехинококоза се наблюдава при:</strong></p><ul><li><strong><span style=\"color: rgb(255, 0, 0)\">Пробив на кистата към плевралната кухина</span></strong></li><li>Нагнояване на кистата от газообразуващи бактерии</li><li>Оформяне на фиброзна капсула</li><li>Пробив на кистата към диафрагмата</li></ul><p><strong>При кой от следните пациенти най-вероятно ще се подозира белодробна ехинококоза?</strong></p><ul><li><strong><span style=\"color: rgb(255, 0, 0)\">Пациент със затруднено дишане и сферично засенчване на рентгенография</span></strong></li><li><strong><span style=\"color: rgb(255, 0, 0)\">10-годишно дете с хронична кашлица и живот в селски район</span></strong></li><li>Студент по медицина със скорошен контакт с ТБ пациент</li><li>Жена с ХИВ инфекция и опортюнистични инфекции</li></ul><br><style></p><p>    body { </p><p>      font-family: \"Open Sans\", Arial, sans-serif; </p><p>      max-width: 1200px; </p><p>      margin: 2rem auto; </p><p>      padding: 0 1rem; </p><p>      line-height: 1.6; </p><p>      color: #1f2937; </p><p>    }</p><p>    h1 { </p><p>      font-weight: 600; </p><p>      font-size: 1.5em;</p><p>      margin-top: 1.5em;</p><p>      margin-bottom: 0.5em;</p><p>      color: #3a5a40;</p><p>      border-bottom: 2px dashed #a3b18a;</p><p>      padding-bottom: 5px;</p><p>    }</p><p>    p { </p><p>      margin: 0.7em 0 1.5em 0; </p><p>      white-space: pre-wrap;</p><p>    }</p><p>    @media (max-width: 768px) {</p><p>      body { font-size: 16px; }</p><p>      h1 { font-size: 1.3em; }</p><p>    }</p><p>  </style>\n<script src=\"https://cdn.jsdelivr.net/npm/katex@0.16.4/dist/katex.min.js\"></script>\n<script src=\"https://cdn.jsdelivr.net/npm/katex@0.16.4/dist/contrib/auto-render.min.js\"></script>\n<script>\nrenderMathInElement(document.body, {\n  delimiters: [\n    {left: '$$', right: '$$', display: true},\n    {left: '$', right: '$', display: false},\n    {left: '\\\\[', right: '\\\\]', display: true},\n    {left: '\\\\(', right: '\\\\)', display: false}\n  ],\n  throwOnError: false\n});\n</script>\n</body>\n</html>","files/Хирургически болести/Гръдна хирургия/1-msg-Заболявания на млечна жлеза.html":"<!DOCTYPE html>\n<html lang=\"bg\">\n<head>\n  <meta charset=\"UTF-8\">\n  <meta name=\"viewport\" content=\"width=device-width, initial-scale=1.0\">\n  <title>d</title>\n  <link rel=\"stylesheet\" href=\"https://cdn.jsdelivr.net/npm/katex@0.16.4/dist/katex.min.css\">\n  <style>\n    body { \n      font-family: \"Open Sans\", Arial, sans-serif; \n      max-width: 1550px; \n      margin: 0.5rem auto; \n      padding: 0 1rem; \n      line-height: 1.6; \n      color: #1f2937; \n    }\n    h1, h2, h3, h4 { \n      font-weight: 600; \n      margin-top: 0.7em;\n      margin-bottom: 0;\n      color: #588157;\n    }\n    h1 { font-size: 1.65em; }\n    h2 { font-size: 1.3em; }\n    h3 { font-size: 1.1em; margin-bottom: 0; }\n    h4 { font-size: 1.05em; margin-bottom: 0; }\n    h1 + h2, h1 + h3, h1 + h4, h2 + h3, h2 + h4, h3 + h4 { margin-top: 0.1em; }\n    p { \n      margin: 0.3em 0; \n      white-space: pre-wrap;\n    }\n    hr {\n      margin: 0.45em 0 0.2em;\n    }\n    hr + h1,\n    hr + h2,\n    hr + h3,\n    hr + h4 {\n      margin-top: 0.2em;\n    }\n    hr + p,\n    hr + ul,\n    hr + ol,\n    hr + blockquote,\n    hr + pre,\n    hr + table {\n      margin-top: 0.08em;\n    }\n    p + ul, p + ol { margin-top: 0.2em; }\n    h1 + p, h2 + p, h3 + p, h4 + p,\n    h1 + ul, h2 + ul, h3 + ul, h4 + ul,\n    h1 + ol, h2 + ol, h3 + ol, h4 + ol { \n      margin-top: 0; \n    }\n    ul, ol { \n      margin: 0.2em 0; \n      padding-left: 1.5em; \n      list-style-position: outside;\n    }\n    li { margin: 0.2em 0; }\n    li p {\n      margin: 0;\n      padding: 0;\n      display: inline;\n    }\n    li > ul, li > ol {\n      margin: 0.15em 0 0 0;\n      padding-left: 1.5em;\n    }\n    ul ul, ul ol, ol ul, ol ol {\n      margin-top: 0.1em;\n      padding-left: 1.5em;\n    }\n    ul ul { list-style-type: circle; }\n    ul ul ul { list-style-type: square; }\n    strong { font-weight: 600; }\n    em { font-style: italic; }\n    code { \n      background: rgba(218, 215, 205, 0.3); \n      padding: 2px 6px; \n      border-radius: 3px; \n      font-family: \"Courier New\", monospace; \n      font-size: 0.9em; \n    }\n    pre {\n      background: rgba(255, 255, 255, 0.5);\n      padding: 12px;\n      border-radius: 4px;\n      overflow-x: auto;\n      margin: 0.5em 0;\n      font-family: \"Courier New\", monospace;\n    }\n    pre code {\n      background: none;\n      padding: 0;\n    }\n    blockquote {\n      border-left: 3px solid #588157;\n      padding-left: 1em;\n      margin: 0.5em 0;\n      font-style: italic;\n      color: #166534;\n    }\n    table { \n      border-collapse: collapse; \n      margin: 0.75em 0; \n      width: 100%; \n      table-layout: auto;\n    }\n    th, td { \n      border: 1px solid rgba(2, 2, 2, 0.2);\n      padding: 6px 10px; \n      text-align: left; \n      vertical-align: top;\n      height: 24px;\n      line-height: 1.2;\n    }\n    thead th { \n      background: rgba(88, 129, 87, 0.13); \n      font-weight: 600; \n    }\n    tbody tr:nth-child(odd) { \n      background: rgba(88, 129, 87, 0.06); \n    }\n    /* Image alignment rules for exported content and md-viewer */\n    img[data-align=\"left\"] {\n      display: block;\n      margin: 8px auto 8px 0;\n    }\n    img[data-align=\"center\"] {\n      display: block;\n      margin: 8px auto;\n    }\n    img[data-align=\"right\"] {\n      display: block;\n      margin: 8px 0 8px auto;\n    }\n    .audio-link-inline {\n      display: inline-flex;\n      align-items: center;\n      gap: 8px;\n      margin: 0.2em 0;\n      max-width: 100%;\n      vertical-align: middle;\n    }\n    .audio-link-icon {\n      width: 28px;\n      height: 28px;\n      border: 1px solid #588157;\n      border-radius: 999px;\n      background: #f0f7f0;\n      color: #2f5d50;\n      cursor: pointer;\n      font-size: 14px;\n      line-height: 1;\n      display: inline-flex;\n      align-items: center;\n      justify-content: center;\n      flex: 0 0 auto;\n    }\n    .audio-link-inline audio {\n      position: absolute;\n      width: 1px;\n      height: 1px;\n      opacity: 0;\n      overflow: hidden;\n      pointer-events: none;\n    }\n    .audio-link-icon img {\n      width: 14px;\n      height: 14px;\n      object-fit: contain;\n      pointer-events: none;\n    }\n    a {\n      color: inherit; /* Changed to inherit */\n      text-decoration: underline;\n    }\n    a:hover {\n      color: #74b673;\n    }\n    /* Keep <p> tags inside list items on same line (as they appear in editor) */\n    li p {\n      margin: 0 !important;\n      padding: 0 !important;\n      display: inline !important;\n    }\n    /* Prevent nested list paragraph issues */\n    li > ul,\n    li > ol {\n      margin: 0.15em 0 0 0;\n      padding-left: 1.5em;\n    }\n    /* Ensure list structure is clean */\n    ul ul, ul ol,\n    ol ul, ol ol {\n      margin-top: 0.1em;\n      padding-left: 1.5em;\n    }\n    @media (max-width: 768px) {\n      body {\n        margin: 0.5rem 0;\n        padding: 0 0.5rem;\n        font-size: 16px;\n      }\n      h1 { font-size: 1.65em; }\n      h2 { font-size: 1.3em; }\n      h3 { font-size: 1.1em; }\n      p { margin: 0.3em 0; }\n      ul, ol { padding-left: 1.5em; }\n      li { margin: 0.2em 0; }\n      table { font-size: 0.9em; }\n      th, td { padding: 6px 10px; }\n    }\n    .editor-note {\n      text-decoration: underline dotted #a3b18a;\n      text-decoration-thickness: 2px;\n      text-underline-offset: 2px;\n      text-decoration-skip-ink: none;\n      cursor: help;\n      position: relative;\n    }\n    .note-tooltip {\n      display: none;\n      position: absolute;\n      background-color: #f0f7f0;\n      color: #1f2937;\n      border: 1px solid #588157;\n      border-radius: 4px;\n      padding: 8px 12px;\n      width: fit-content;\n      max-width: min(700px, calc(100vw - 20px));\n      max-height: calc(100vh - 20px);\n      overflow: auto;\n      box-sizing: border-box;\n      box-shadow: 0 2px 8px rgba(0,0,0,0.2);\n      z-index: 10000;\n      font-size: 0.9em;\n      line-height: 1.4;\n      word-wrap: break-word;\n    }\n    .note-tooltip ul, .note-tooltip ol {\n      margin: 0 !important;\n      padding-left: 20px !important;\n    }\n    .note-tooltip li {\n      margin: 0 0 0.1em 0 !important;\n      padding: 0 !important;\n      line-height: 1.2 !important;\n    }\n    .note-tooltip li:last-child {\n      margin-bottom: 0 !important;\n    }\n  </style>\n  <script>\n    document.addEventListener('DOMContentLoaded', function() {\n      const tooltip = document.createElement('div');\n      tooltip.className = 'note-tooltip';\n      document.body.appendChild(tooltip);\n\n      function parseNoteMarkdown(text) {\n        if (!text) return '';\n        \n        let lines = text.split('\\n');\n        let html = [];\n        let stack = [];\n        \n        for (let i = 0; i < lines.length; i++) {\n          let line = lines[i];\n          \n          let indentMatch = line.match(/^(\\s*)/);\n          let indent = indentMatch ? indentMatch[1].length : 0;\n          let content = line.trim();\n          \n          let isUl = /^[-*]\\s+(.+)/.test(content);\n          let isOl = /^\\d+\\.\\s+(.+)/.test(content);\n          \n          if (isUl || isOl) {\n            let listType = isUl ? 'ul' : 'ol';\n            let match = isUl ? content.match(/^[-*]\\s+(.+)/) : content.match(/^\\d+\\.\\s+(.+)/);\n            let itemText = match[1];\n            \n            if (stack.length === 0) {\n              stack.push({ type: listType, indent: indent });\n              html.push('<' + listType + '>');\n            } else {\n              let last = stack[stack.length - 1];\n              \n              if (indent > last.indent) {\n                stack.push({ type: listType, indent: indent });\n                html.push('<' + listType + '>');\n              } else if (indent < last.indent) {\n                while (stack.length > 0 && stack[stack.length - 1].indent > indent) {\n                  let closed = stack.pop();\n                  html.push('</' + closed.type + '>');\n                }\n                if (stack.length === 0 || stack[stack.length - 1].indent !== indent) {\n                   stack.push({ type: listType, indent: indent });\n                   html.push('<' + listType + '>');\n                } else if (stack[stack.length - 1].type !== listType) {\n                   let closed = stack.pop();\n                   html.push('</' + closed.type + '>');\n                   stack.push({ type: listType, indent: indent });\n                   html.push('<' + listType + '>');\n                }\n              } else {\n                if (last.type !== listType) {\n                  let closed = stack.pop();\n                  html.push('</' + closed.type + '>');\n                  stack.push({ type: listType, indent: indent });\n                  html.push('<' + listType + '>');\n                }\n              }\n            }\n            html.push('<li>' + itemText + '</li>');\n          } else {\n            if (content !== '') {\n               while (stack.length > 0) {\n                 let closed = stack.pop();\n                 html.push('</' + closed.type + '>');\n               }\n            }\n            if (/^#{1,4}\\s+/.test(content)) {\n              const headingMatch = content.match(/^(#{1,4})\\s+(.+)$/);\n              if (headingMatch) {\n                const level = headingMatch[1].length;\n                html.push('<h' + level + '>' + headingMatch[2] + '</h' + level + '>');\n              }\n            } else if (content) {\n              html.push(content + '<br>');\n            } else {\n              html.push('<br>');\n            }\n          }\n        }\n        \n        while (stack.length > 0) {\n          let closed = stack.pop();\n          html.push('</' + closed.type + '>');\n        }\n        \n        let result = html.join('')\n          .replace(/!\\[(.*?)\\]\\((.*?)\\)/g, '<img src=\"$2\" alt=\"$1\">')\n          .replace(/\\*\\*(.+?)\\*\\*/g, '<strong>$1</strong>')\n          .replace(/__(.+?)__/g, '<strong>$1</strong>')\n          .replace(/\\*(.+?)\\*/g, '<em>$1</em>')\n          .replace(/_(.+?)_/g, '<em>$1</em>')\n          .replace(/`(.+?)`/g, '<code>$1</code>')\n          .replace(/\\[(.+?)\\]\\((.+?)\\)/g, '<a href=\"$2\" target=\"_blank\">$1</a>');\n        \n        result = result\n          .replace(/<br><ul>/g, '<ul>')\n          .replace(/<br><ol>/g, '<ol>')\n          .replace(/</ul><br>/g, '</ul>')\n          .replace(/</ol><br>/g, '</ol>');\n        \n        return result;\n      }\n\n      document.body.addEventListener('mouseover', function(e) {\n        if (e.target.classList.contains('editor-note')) {\n          const note = e.target.dataset.note;\n          if (note) {\n            tooltip.innerHTML = parseNoteMarkdown(note);\n            tooltip.style.display = 'block';\n            const rect = e.target.getBoundingClientRect();\n            const tooltipRect = tooltip.getBoundingClientRect();\n            const pageX = window.scrollX || window.pageXOffset;\n            const pageY = window.scrollY || window.pageYOffset;\n            const maxLeft = pageX + window.innerWidth - tooltipRect.width - 10;\n            const minLeft = pageX + 10;\n\n            let left = rect.left + pageX;\n            if (left > maxLeft) left = maxLeft;\n            if (left < minLeft) left = minLeft;\n\n            let top = rect.bottom + pageY + 6;\n            const maxTop = pageY + window.innerHeight - tooltipRect.height - 10;\n            if (top > maxTop) {\n              top = rect.top + pageY - tooltipRect.height - 6;\n            }\n            if (top < pageY + 10) top = pageY + 10;\n\n            tooltip.style.left = left + 'px';\n            tooltip.style.top = top + 'px';\n          }\n        }\n      });\n\n      document.body.addEventListener('mouseout', function(e) {\n        if (e.target.classList.contains('editor-note')) {\n          setTimeout(() => {\n            if (!tooltip.matches(':hover')) {\n              tooltip.style.display = 'none';\n            }\n          }, 100);\n        }\n      });\n\n      tooltip.addEventListener('mouseleave', function() {\n        tooltip.style.display = 'none';\n      });\n    });\n  </script>\n</head>\n<body>\n<h1 style=\"text-align: center\">Карцином на млечната жлеза: Диагностика, лечение и профилактика</h1><h2>1. Дефиниция и същност</h2><p>Карциномът на млечната жлеза представлява злокачествено новообразувание, което произлиза от епителните клетки на каналите (<strong>дуктален карцином</strong>) или на лобулите (<strong>лобуларен карцином</strong>) на жлезната тъкан. Заболяването се характеризира с неконтролиран клетъчен растеж, способност за локална инвазия в съседни тъкани и потенциал за метастазиране по лимфен и кръвен път в далечни органи.</p><hr><h2>2. Епидемиология</h2><p>Епидемиологичните данни подчертават изключителната социална и медицинска значимост на заболяването:</p><ul><li><strong>Честота:</strong> Това е най-честото злокачествено заболяване при жените в световен мащаб и в България, съставляващо приблизително <strong>25%</strong> от всички онкологични локализации при жената.</li><li><strong>Статистика за България:</strong> Рискът от развитие на заболяването е <strong>1 на всеки 20 жени</strong>. </li><li><strong>Смъртност:</strong> Карциномът на гърдата е <strong>водещата причина за смъртност</strong> при жените във възрастовата група <strong>35–55 години</strong> и втората водеща причина за смъртност сред жените от всички възрасти (след сърдечно-съдовите заболявания и белодробния карцином в някои региони).</li><li><strong>Възрастов профил:</strong> Заболеваемостта рязко нараства след 50-годишна възраст, като пикът е в групата 60–70 години. Въпреки това, в последните десетилетия се наблюдава тенденция към „подмладяване“ на болестта.</li></ul><hr><h2>3. Етиология и рискови фактори</h2><p>Етиологията е мултифакторна, като се прави разграничение между генетична предразположеност и фактори на околната среда:</p><h3>А. Биологични и генетични фактори</h3><ul><li><strong>Пол и възраст:</strong> Основен рисков фактор (съотношение жени към мъже е 100:1). Рискът нараства правопропорционално с възрастта.</li><li><strong>Фамилна обремененост:</strong> Наличието на първа степен родственици (майка, сестра, дъщеря) с рак на гърдата повишава риска до <strong>3 пъти</strong>. <span class=\"editor-note\" data-note=\"![Image](https://media.licdn.com/dms/image/v2/D5622AQHGnONIPSTI7w/feedshare-shrink_800/B56Z0BadqdHIAg-/0/1773845207966?e=2147483647&amp;v=beta&amp;t=_WCLA2Da4Thhudw0-TvwJ4Qjv5zUzWYz-RIgZwb68Wg &quot;width=40%&quot;)\" id=\"note-1774006638751-0\">Генетичните мутации в гените <strong>BRCA1</strong> и <strong>BRCA2</strong> са свързани с висок наследствен риск</span>.</li><li><strong>Хормонален статус:</strong> Продължителната експозиция на естрогени е ключов фактор. Това включва:</li><ul><li>Ранно менархе (първа менструация преди 12-годишна възраст).</li><li>Късна менопауза (след 50–55 години).</li></ul></ul><h3>Б. Репродуктивни фактори</h3><ul><li><strong>Късно първо раждане:</strong> Раждането на първо дете след 30-годишна възраст или липсата на раждания (нулепаритет) статистически повишават риска.</li><li><strong>Кърмене:</strong> Липсата на кърмене или краткотрайното такова се счита за неблагоприятен фактор.</li></ul><h3>В. Екзогенни фактори и начин на живот</h3><ul><li><strong>Хормонална заместителна терапия (ХЗТ):</strong> Продължителният прием на хормони след менопаузата.</li><li><strong>Затлъстяване:</strong> Особено при жени в постменопауза, поради периферната конверсия на андрогени в естрогени в мастната тъкан.</li><li><strong>Диета и вредни навици:</strong> Висока консумация на наситени мазнини, системен прием на алкохол и тютюнопушене.</li><li><strong>Придружаващи заболявания:</strong> Заболявания на яйчниците, щитовидната жлеза, захарен диабет и някои доброкачествени дисплазии на гърдата.</li></ul><hr><h2>4. Анатомични основи и локализация</h2><p>Млечната жлеза е разположена върху предната гръдна стена. За клинични цели тя се разделя на четири квадранта чрез две перпендикулярни линии, пресичащи се в мамилата (пети квадрант).</p><p>Най-честата локализация на туморния процес е в горен външен квадрант (50%).<br><img src=\"https://files.coursebook.lol/%D0%9F%D0%B0%D0%B8%D1%81%D0%B8%D0%B9/2026-03-20/text-editor-images/2026/03/1773998115279-image.png\" alt=\"https://files.coursebook.lol/%D0%9F%D0%B0%D0%B8%D1%81%D0%B8%D0%B9/2026-03-20/text-editor-images/2026/03/1773998115279-image.png\" data-original-src=\"https://files.coursebook.lol/%D0%9F%D0%B0%D0%B8%D1%81%D0%B8%D0%B9/2026-03-20/text-editor-images/2026/03/1773998115279-image.png\" data-width=\"70\" data-align=\"left\" style=\"width: 429.8px; max-width: none; height: auto; display: block; float: none; margin: 8px auto 8px 0px\"></p><hr><h2>5. Лимфен дренаж (Регионални лимфни възли)</h2><p>Разпространението по лимфен път е основен механизъм за метастазиране. Регионалните лимфни възли се класифицират в три основни нива спрямо <em>m. pectoralis minor</em>:</p><ol><li><strong>Първо ниво (Долна аксила):</strong> Лимфни възли, разположени латерално от външния ръб на <em>m. pectoralis minor</em>.</li><li><strong>Второ ниво (Средна аксила):</strong> Лимфни възли, разположени между външния и вътрешния ръб на <em>m. pectoralis minor</em>, както и интерпекторалните възли (на Rotter).</li><li><strong>Трето ниво (Апикални):</strong> Лимфни възли, разположени медиално от вътрешния ръб на <em>m. pectoralis minor</em>, включително субклавикуларните възли.</li></ol><p><img src=\"https://scontent.fvar1-1.fna.fbcdn.net/v/t1.15752-9/628080555_900494782850693_8645142310468398192_n.jpg?_nc_cat=103&amp;ccb=1-7&amp;_nc_sid=9f807c&amp;_nc_ohc=eSvg5tAiDdMQ7kNvwGrvNkC&amp;_nc_oc=Adqr1XgXQP9v1aBqQvElV4AkhdaAGRxMeODdNUhLyxZomN4AgJ_SlIjgpQWbnLuQScM&amp;_nc_zt=23&amp;_nc_ht=scontent.fvar1-1.fna&amp;_nc_ss=7a30f&amp;oh=03_Q7cD4wGE7d36_99jubtmQsHXuJEdRZC_5xOA7WkiQTq5m3zLEw&amp;oe=69E49CE0\" alt=\"https://scontent.fvar1-1.fna.fbcdn.net/v/t1.15752-9/628080555_900494782850693_8645142310468398192_n.jpg?_nc_cat=103&amp;ccb=1-7&amp;_nc_sid=9f807c&amp;_nc_ohc=eSvg5tAiDdMQ7kNvwGrvNkC&amp;_nc_oc=Adqr1XgXQP9v1aBqQvElV4AkhdaAGRxMeODdNUhLyxZomN4AgJ_SlIjgpQWbnLuQScM&amp;_nc_zt=23&amp;_nc_ht=scontent.fvar1-1.fna&amp;_nc_ss=7a30f&amp;oh=03_Q7cD4wGE7d36_99jubtmQsHXuJEdRZC_5xOA7WkiQTq5m3zLEw&amp;oe=69E49CE0\" data-original-src=\"https://scontent.fvar1-1.fna.fbcdn.net/v/t1.15752-9/628080555_900494782850693_8645142310468398192_n.jpg?_nc_cat=103&amp;ccb=1-7&amp;_nc_sid=9f807c&amp;_nc_ohc=eSvg5tAiDdMQ7kNvwGrvNkC&amp;_nc_oc=Adqr1XgXQP9v1aBqQvElV4AkhdaAGRxMeODdNUhLyxZomN4AgJ_SlIjgpQWbnLuQScM&amp;_nc_zt=23&amp;_nc_ht=scontent.fvar1-1.fna&amp;_nc_ss=7a30f&amp;oh=03_Q7cD4wGE7d36_99jubtmQsHXuJEdRZC_5xOA7WkiQTq5m3zLEw&amp;oe=69E49CE0\" data-width=\"40\" data-align=\"left\" style=\"width: 471.6px; max-width: none; height: auto; display: block; float: none; margin: 8px auto 8px 0px\"></p><hr><h2>6. Класификация на заболяването</h2><h3>А. Патоанатомични (хистологични) форми</h3><p>Злокачествените процеси се разделят на неинвазивни и инвазивни форми:</p><ul><li><strong>Карциноми \"In situ\" (неинвазивни):</strong></li><ul><li>Интрадуктален карцином \"in situ\".</li><li>Лобуларен карцином \"in situ\" (<u>свързан с 8-10 пъти по-висок риск от развитие на рак и в двете гърди</u>).</li></ul><li><strong>Инвазивни карциноми:</strong></li><ul><li>Инвазивен дуктален карцином – най-чест (<strong>70%</strong>).</li><li>Инвазивен лобуларен карцином (<strong>10%</strong>).</li><li>Медуларен карцином (5–7%).</li><li>Муцинозен (желатинозен) аденокарцином (3%).</li><li>Тубуларен аденокарцином (2%).</li><li>Инфламаторен карцином (под 2% – с най-лоша прогноза).</li></ul><li><strong>Болест на Paget:</strong> Злокачествено засягане на мамилата и ареолата.</li></ul><h3>Б. TNM Класификация (Основни категории)</h3><p>Използва се за определяне на клиничния стадий и прогнозата:</p><ul><li><strong>T (Първичен тумор):</strong></li><ul><li><strong>Tis:</strong> Карцином \"in situ\".</li><li><strong>T1:</strong> Тумор ≤ 2 cm.</li><li><strong>T2:</strong> Тумор &gt; 2 cm, но ≤ 5 cm.</li><li><strong>T3:</strong> Тумор &gt; 5 cm.</li><li><strong>T4:</strong> Тумор с всякакъв размер, ангажиращ гръдната стена (T4a) или кожата (едем, улцерация – T4b).</li></ul><li><strong>N (Регионални лимфни възли):</strong></li><ul><li><strong>N0:</strong> Няма метастази в регионалните възли.</li><li><strong>N1:</strong> Метастази в 1–3 подвижни аксиларни лимфни възела.</li><li><strong>N2:</strong> Метастази в 4–9 аксиларни възела.</li><li><strong>N3:</strong> Метастази в ≥ 10 аксиларни възела или в супраклавикуларни възли.</li></ul><li><strong>M (Далечни метастази):</strong></li><ul><li><strong>M0:</strong> Няма данни за далечни метастази.</li><li><strong>M1:</strong> Налични далечни метастази (най-често в <strong>черен дроб, кости, бял дроб</strong>).</li></ul></ul><hr><h2>7. Клинична картина (Симптоматика)</h2><p>Клиничната презентация варира в зависимост от еволюцията на тумора:</p><ul><li><strong>Ранни симптоми:</strong></li><ul><li>Наличие на безболезнена, плътна формация с неясни граници.</li><li>Лека асиметрия на млечните жлези, забележима при вдигане на ръцете.</li></ul><li><strong>Промени в кожата:</strong></li><ul><li>Симптом на „портокаловата кожа“ (peau d'orange) – дължи се на блокада на кожните лимфни пътища.</li><li>Фиксация или хлътване на кожата (придърпване от тумора).</li><li>Зачервяване, едем илиулцерация.</li></ul><li><strong>Промени в мамилата:</strong></li><ul><li>Ретракция или девиация на зърното.</li><li>Секреция – особено подозрителна, ако е хеморагична и едностранна.</li><li>Екзематозни промени (характерни за болестта на Paget).</li></ul></ul><hr><h2>8. Диагностичен алгоритъм</h2><p>Процесът е линеен и цели максимална точност преди започване на лечение:</p><ul><li><strong>Клиничен преглед:</strong></li><ul><li>Системен оглед и палпация на жлезите в изправено и легнало положение.</li><li>Изследване на регионалните лимфни басейни (аксиларни, надключични).</li></ul><li><strong>Образна диагностика:</strong></li><ul><li><strong>Мамография:</strong> Основен рентгенов метод; визуализира огнищни сенки и микрокалцификати.</li><li><strong>Ехография:</strong> Използва се за диференциране на кисти от солидни тумори; водещ метод при млади пациентки.</li></ul><li><strong>Морфологично потвърждение:</strong></li><ul><li><strong>Тънкоиглена аспирационна биопсия (ТАБ):</strong> За цитологично изследване.</li><li><strong>Core-биопсия:</strong> Извличане на тъканен стълб за хистологична диагноза и определяне на биологичния профил (рецептори).</li></ul></ul><hr><h2>9. Диференциална диагноза</h2><p>Важно е карциномът да се разграничи от доброкачествени процеси:</p><ul><li><strong>Фиброаденом:</strong> Най-чест при млади жени; гладък, подвижен и с ясни граници.</li><li><strong>Кисти:</strong> Често болезнени преди цикъл, изчезват след аспирация.</li><li><strong>Мастит и абсцес:</strong> Протичат с висока температура, болка и локално зачервяване.</li><li><strong>Мастна некроза:</strong> Обикновено след преживяна травма.</li></ul><hr><h2>10. Прогноза и преживяемост</h2><p>Прогнозата зависи пряко от стадия на откриване и биологичните характеристики на тумора:</p><ul><li><strong>Преживяемост:</strong>&nbsp;</li><ul><li>При локализиран процес (без метастази) 5-годишната преживяемост е над 95%.</li><li>При наличие на далечни метастази (Стадий IV) процентът спада драстично до около 16%.</li></ul><li><strong>Прогностични фактори:</strong></li><ul><li>Размер на тумора (Т).</li><li>Брой засегнати лимфни възли (N).</li><li>Хормонален статус (ER/PR) и HER2 експресия.</li><li>Степен на диференциация на клетките (G - Grade).</li></ul></ul><br><br><br><style></p><p>    body { </p><p>      font-family: \"Open Sans\", Arial, sans-serif; </p><p>      max-width: 1200px; </p><p>      margin: 2rem auto; </p><p>      padding: 0 1rem; </p><p>      line-height: 1.6; </p><p>      color: #1f2937; </p><p>    }</p><p>    h1 { </p><p>      font-weight: 600; </p><p>      font-size: 1.5em;</p><p>      margin-top: 1.5em;</p><p>      margin-bottom: 0.5em;</p><p>      color: #3a5a40;</p><p>      border-bottom: 2px dashed #a3b18a;</p><p>      padding-bottom: 5px;</p><p>    }</p><p>    p { </p><p>      margin: 0.7em 0 1.5em 0; </p><p>      white-space: pre-wrap;</p><p>    }</p><p>    @media (max-width: 768px) {</p><p>      body { font-size: 16px; }</p><p>      h1 { font-size: 1.3em; }</p><p>    }</p><p>  </style>\n<script src=\"https://cdn.jsdelivr.net/npm/katex@0.16.4/dist/katex.min.js\"></script>\n<script src=\"https://cdn.jsdelivr.net/npm/katex@0.16.4/dist/contrib/auto-render.min.js\"></script>\n<script>\nrenderMathInElement(document.body, {\n  delimiters: [\n    {left: '$$', right: '$$', display: true},\n    {left: '$', right: '$', display: false},\n    {left: '\\\\[', right: '\\\\]', display: true},\n    {left: '\\\\(', right: '\\\\)', display: false}\n  ],\n  throwOnError: false\n});\n</script>\n</body>\n</html>","files/Хирургически болести/Гръдна хирургия/2-msg-Хирургически заболявания на щитовидната жлеза.html":"<!DOCTYPE html>\n<html lang=\"bg\">\n<head>\n  <meta charset=\"UTF-8\">\n  <meta name=\"viewport\" content=\"width=device-width, initial-scale=1.0\">\n  <title>Хирургически заболявания на щитовидната жлеза</title>\n  <link rel=\"stylesheet\" href=\"https://cdn.jsdelivr.net/npm/katex@0.16.4/dist/katex.min.css\">\n  <style>\n    body { \n      font-family: \"Open Sans\", Arial, sans-serif; \n      max-width: 1550px; \n      margin: 0.5rem auto; \n      padding: 0 1rem; \n      line-height: 1.6; \n      color: #1f2937; \n    }\n    h1, h2, h3, h4 { \n      font-weight: 600; \n      margin-top: 0.7em;\n      margin-bottom: 0;\n      color: #588157;\n    }\n    h1 { font-size: 1.65em; }\n    h2 { font-size: 1.3em; }\n    h3 { font-size: 1.1em; margin-bottom: 0; }\n    h4 { font-size: 1.05em; margin-bottom: 0; }\n    h1 + h2, h1 + h3, h1 + h4, h2 + h3, h2 + h4, h3 + h4 { margin-top: 0.1em; }\n    p { \n      margin: 0.3em 0; \n      white-space: pre-wrap;\n    }\n    hr {\n      margin: 0.45em 0 0.2em;\n    }\n    hr + h1,\n    hr + h2,\n    hr + h3,\n    hr + h4 {\n      margin-top: 0.2em;\n    }\n    hr + p,\n    hr + ul,\n    hr + ol,\n    hr + blockquote,\n    hr + pre,\n    hr + table {\n      margin-top: 0.08em;\n    }\n    p + ul, p + ol { margin-top: 0.2em; }\n    h1 + p, h2 + p, h3 + p, h4 + p,\n    h1 + ul, h2 + ul, h3 + ul, h4 + ul,\n    h1 + ol, h2 + ol, h3 + ol, h4 + ol { \n      margin-top: 0; \n    }\n    ul, ol { \n      margin: 0.2em 0; \n      padding-left: 1.5em; \n      list-style-position: outside;\n    }\n    li { margin: 0.2em 0; }\n    li p {\n      margin: 0;\n      padding: 0;\n      display: inline;\n    }\n    li > ul, li > ol {\n      margin: 0.15em 0 0 0;\n      padding-left: 1.5em;\n    }\n    ul ul, ul ol, ol ul, ol ol {\n      margin-top: 0.1em;\n      padding-left: 1.5em;\n    }\n    ul ul { list-style-type: circle; }\n    ul ul ul { list-style-type: square; }\n    strong { font-weight: 600; }\n    em { font-style: italic; }\n    code { \n      background: rgba(218, 215, 205, 0.3); \n      padding: 2px 6px; \n      border-radius: 3px; \n      font-family: \"Courier New\", monospace; \n      font-size: 0.9em; \n    }\n    pre {\n      background: rgba(255, 255, 255, 0.5);\n      padding: 12px;\n      border-radius: 4px;\n      overflow-x: auto;\n      margin: 0.5em 0;\n      font-family: \"Courier New\", monospace;\n    }\n    pre code {\n      background: none;\n      padding: 0;\n    }\n    blockquote {\n      border-left: 3px solid #588157;\n      padding-left: 1em;\n      margin: 0.5em 0;\n      font-style: italic;\n      color: #166534;\n    }\n    table { \n      border-collapse: collapse; \n      margin: 0.75em 0; \n      width: 100%; \n      table-layout: auto;\n    }\n    th, td { \n      border: 1px solid rgba(2, 2, 2, 0.2);\n      padding: 6px 10px; \n      text-align: left; \n      vertical-align: top;\n      height: 24px;\n      line-height: 1.2;\n    }\n    thead th { \n      background: rgba(88, 129, 87, 0.13); \n      font-weight: 600; \n    }\n    tbody tr:nth-child(odd) { \n      background: rgba(88, 129, 87, 0.06); \n    }\n    /* Image alignment rules for exported content and md-viewer */\n    img[data-align=\"left\"] {\n      display: block;\n      margin: 8px auto 8px 0;\n    }\n    img[data-align=\"center\"] {\n      display: block;\n      margin: 8px auto;\n    }\n    img[data-align=\"right\"] {\n      display: block;\n      margin: 8px 0 8px auto;\n    }\n    .audio-link-inline {\n      display: inline-flex;\n      align-items: center;\n      gap: 8px;\n      margin: 0.2em 0;\n      max-width: 100%;\n      vertical-align: middle;\n    }\n    .audio-link-icon {\n      width: 28px;\n      height: 28px;\n      border: 1px solid #588157;\n      border-radius: 999px;\n      background: #f0f7f0;\n      color: #2f5d50;\n      cursor: pointer;\n      font-size: 14px;\n      line-height: 1;\n      display: inline-flex;\n      align-items: center;\n      justify-content: center;\n      flex: 0 0 auto;\n    }\n    .audio-link-inline audio {\n      position: absolute;\n      width: 1px;\n      height: 1px;\n      opacity: 0;\n      overflow: hidden;\n      pointer-events: none;\n    }\n    .audio-link-icon img {\n      width: 14px;\n      height: 14px;\n      object-fit: contain;\n      pointer-events: none;\n    }\n    a {\n      color: inherit; /* Changed to inherit */\n      text-decoration: underline;\n    }\n    a:hover {\n      color: #74b673;\n    }\n    /* Keep <p> tags inside list items on same line (as they appear in editor) */\n    li p {\n      margin: 0 !important;\n      padding: 0 !important;\n      display: inline !important;\n    }\n    /* Prevent nested list paragraph issues */\n    li > ul,\n    li > ol {\n      margin: 0.15em 0 0 0;\n      padding-left: 1.5em;\n    }\n    /* Ensure list structure is clean */\n    ul ul, ul ol,\n    ol ul, ol ol {\n      margin-top: 0.1em;\n      padding-left: 1.5em;\n    }\n    @media (max-width: 768px) {\n      body {\n        margin: 0.5rem 0;\n        padding: 0 0.5rem;\n        font-size: 16px;\n      }\n      h1 { font-size: 1.65em; }\n      h2 { font-size: 1.3em; }\n      h3 { font-size: 1.1em; }\n      p { margin: 0.3em 0; }\n      ul, ol { padding-left: 1.5em; }\n      li { margin: 0.2em 0; }\n      table { font-size: 0.9em; }\n      th, td { padding: 6px 10px; }\n    }\n    .editor-note {\n      text-decoration: underline dotted #a3b18a;\n      text-decoration-thickness: 2px;\n      text-underline-offset: 2px;\n      text-decoration-skip-ink: none;\n      cursor: help;\n      position: relative;\n    }\n    .note-tooltip {\n      display: none;\n      position: absolute;\n      background-color: #f0f7f0;\n      color: #1f2937;\n      border: 1px solid #588157;\n      border-radius: 4px;\n      padding: 8px 12px;\n      width: fit-content;\n      max-width: min(700px, calc(100vw - 20px));\n      max-height: calc(100vh - 20px);\n      overflow: auto;\n      box-sizing: border-box;\n      box-shadow: 0 2px 8px rgba(0,0,0,0.2);\n      z-index: 10000;\n      font-size: 0.9em;\n      line-height: 1.4;\n      word-wrap: break-word;\n    }\n    .note-tooltip ul, .note-tooltip ol {\n      margin: 0 !important;\n      padding-left: 20px !important;\n    }\n    .note-tooltip li {\n      margin: 0 0 0.1em 0 !important;\n      padding: 0 !important;\n      line-height: 1.2 !important;\n    }\n    .note-tooltip li:last-child {\n      margin-bottom: 0 !important;\n    }\n  </style>\n  <script>\n    document.addEventListener('DOMContentLoaded', function() {\n      const tooltip = document.createElement('div');\n      tooltip.className = 'note-tooltip';\n      document.body.appendChild(tooltip);\n\n      function parseNoteMarkdown(text) {\n        if (!text) return '';\n        \n        let lines = text.split('\\n');\n        let html = [];\n        let stack = [];\n        \n        for (let i = 0; i < lines.length; i++) {\n          let line = lines[i];\n          \n          let indentMatch = line.match(/^(\\s*)/);\n          let indent = indentMatch ? indentMatch[1].length : 0;\n          let content = line.trim();\n          \n          let isUl = /^[-*]\\s+(.+)/.test(content);\n          let isOl = /^\\d+\\.\\s+(.+)/.test(content);\n          \n          if (isUl || isOl) {\n            let listType = isUl ? 'ul' : 'ol';\n            let match = isUl ? content.match(/^[-*]\\s+(.+)/) : content.match(/^\\d+\\.\\s+(.+)/);\n            let itemText = match[1];\n            \n            if (stack.length === 0) {\n              stack.push({ type: listType, indent: indent });\n              html.push('<' + listType + '>');\n            } else {\n              let last = stack[stack.length - 1];\n              \n              if (indent > last.indent) {\n                stack.push({ type: listType, indent: indent });\n                html.push('<' + listType + '>');\n              } else if (indent < last.indent) {\n                while (stack.length > 0 && stack[stack.length - 1].indent > indent) {\n                  let closed = stack.pop();\n                  html.push('</' + closed.type + '>');\n                }\n                if (stack.length === 0 || stack[stack.length - 1].indent !== indent) {\n                   stack.push({ type: listType, indent: indent });\n                   html.push('<' + listType + '>');\n                } else if (stack[stack.length - 1].type !== listType) {\n                   let closed = stack.pop();\n                   html.push('</' + closed.type + '>');\n                   stack.push({ type: listType, indent: indent });\n                   html.push('<' + listType + '>');\n                }\n              } else {\n                if (last.type !== listType) {\n                  let closed = stack.pop();\n                  html.push('</' + closed.type + '>');\n                  stack.push({ type: listType, indent: indent });\n                  html.push('<' + listType + '>');\n                }\n              }\n            }\n            html.push('<li>' + itemText + '</li>');\n          } else {\n            if (content !== '') {\n               while (stack.length > 0) {\n                 let closed = stack.pop();\n                 html.push('</' + closed.type + '>');\n               }\n            }\n            if (/^#{1,4}\\s+/.test(content)) {\n              const headingMatch = content.match(/^(#{1,4})\\s+(.+)$/);\n              if (headingMatch) {\n                const level = headingMatch[1].length;\n                html.push('<h' + level + '>' + headingMatch[2] + '</h' + level + '>');\n              }\n            } else if (content) {\n              html.push(content + '<br>');\n            } else {\n              html.push('<br>');\n            }\n          }\n        }\n        \n        while (stack.length > 0) {\n          let closed = stack.pop();\n          html.push('</' + closed.type + '>');\n        }\n        \n        let result = html.join('')\n          .replace(/!\\[(.*?)\\]\\((.*?)\\)/g, '<img src=\"$2\" alt=\"$1\">')\n          .replace(/\\*\\*(.+?)\\*\\*/g, '<strong>$1</strong>')\n          .replace(/__(.+?)__/g, '<strong>$1</strong>')\n          .replace(/\\*(.+?)\\*/g, '<em>$1</em>')\n          .replace(/_(.+?)_/g, '<em>$1</em>')\n          .replace(/`(.+?)`/g, '<code>$1</code>')\n          .replace(/\\[(.+?)\\]\\((.+?)\\)/g, '<a href=\"$2\" target=\"_blank\">$1</a>');\n        \n        result = result\n          .replace(/<br><ul>/g, '<ul>')\n          .replace(/<br><ol>/g, '<ol>')\n          .replace(/</ul><br>/g, '</ul>')\n          .replace(/</ol><br>/g, '</ol>');\n        \n        return result;\n      }\n\n      document.body.addEventListener('mouseover', function(e) {\n        if (e.target.classList.contains('editor-note')) {\n          const note = e.target.dataset.note;\n          if (note) {\n            tooltip.innerHTML = parseNoteMarkdown(note);\n            tooltip.style.display = 'block';\n            const rect = e.target.getBoundingClientRect();\n            const tooltipRect = tooltip.getBoundingClientRect();\n            const pageX = window.scrollX || window.pageXOffset;\n            const pageY = window.scrollY || window.pageYOffset;\n            const maxLeft = pageX + window.innerWidth - tooltipRect.width - 10;\n            const minLeft = pageX + 10;\n\n            let left = rect.left + pageX;\n            if (left > maxLeft) left = maxLeft;\n            if (left < minLeft) left = minLeft;\n\n            let top = rect.bottom + pageY + 6;\n            const maxTop = pageY + window.innerHeight - tooltipRect.height - 10;\n            if (top > maxTop) {\n              top = rect.top + pageY - tooltipRect.height - 6;\n            }\n            if (top < pageY + 10) top = pageY + 10;\n\n            tooltip.style.left = left + 'px';\n            tooltip.style.top = top + 'px';\n          }\n        }\n      });\n\n      document.body.addEventListener('mouseout', function(e) {\n        if (e.target.classList.contains('editor-note')) {\n          setTimeout(() => {\n            if (!tooltip.matches(':hover')) {\n              tooltip.style.display = 'none';\n            }\n          }, 100);\n        }\n      });\n\n      tooltip.addEventListener('mouseleave', function() {\n        tooltip.style.display = 'none';\n      });\n    });\n  </script>\n</head>\n<body>\n<blockquote>Сравнително съкратено, лекцията е много подробна</blockquote><h1 style=\"text-align: center\">Заболявания на щитовидната жлеза</h1><h2>1. Анатомия и топография</h2><p>Щитовидната жлеза (<em>Glandula thyroidea</em>) е най-голямата жлеза с вътрешна секреция.</p><ul><li><strong>Местоположение:</strong> Разположена е в предната шийна област, като обхваща предната и страничните повърхности на ларинкса и началната част на трахеята.</li><li><strong>Структура:</strong></li><ul><li><strong>Два странични лоба:</strong> Десен и ляв (<em>Lobus dexter et sinister</em>). Горните им полюси достигат средата на тиреоидния хрущял, а долните – до 5-6-о трахеално хръщялно полупръстенче.</li><li><strong>Истмус (Провлак):</strong> Тясна част, свързваща двата лоба на нивото на 2-ро и 3-то трахеално пръстенче.</li><li><strong>Lobus pyramidalis:</strong> Непостоянен трети лоб (при 30-50% от случаите), който тръгва от истмуса нагоре.</li></ul><li><strong>Капсула:</strong> Жлезата е обвита от тънка фиброзна капсула (<em>Capsula propria</em>), от която навлизат прегради в паренхима. Тя е фиксирана към ларинкса и трахеята чрез съединителнотъканни връзки (лигаменти на Berry), поради което се движи при гълтане.</li></ul><h2>2. Паращитовидни жлези (Glandulae parathyroideae)</h2><p>Тези жлези са от критично значение за калциево-фосфорната обмяна.</p><ul><li><strong>Брой и разположение:</strong> Обикновено са <strong>четири</strong> на брой – две горни и две долни. Намират се по задната повърхност на лобовете на щитовидната жлеза, между нейната капсула и фасцията на шията.</li><li><strong>Размери:</strong> Малки, лещовидни телца с размери около 6х3х2 мм и кафеникав цвят.</li><li><strong>Вариабилност:</strong> Позицията им може да варира (ектопия) – могат да бъдат открити в медиастинума или в самата тъкан на щитовидната жлеза.</li><li><strong>Функция:</strong> Секретират паратхормон (PTH), който повишава нивата на калций в кръвта. При хирургична интервенция е жизненоважно да бъдат запазени, за да се избегне хипокалциемия.</li></ul><h2>3. Кръвоснабдяване (Васкуларизация)</h2><p>Щитовидната жлеза е един от най-обилно кръвоснабдените органи в човешкото тяло.</p><ul><li><strong>Артериално захранване:</strong> Извършва се от две двойки основни артерии:</li><ol><li><strong>A. thyroidea superior (Горна тиреоидна артерия):</strong> Първият клон на <em>a. carotis externa</em>. Спуска се към горния полюс на жлезата.</li><li><strong>A. thyroidea inferior (Долна тиреоидна артерия):</strong> Клон на <em>truncus thyrocervicalis</em> (от <em>a. subclavia</em>). Тя е по-мощна и захранва долните части на жлезата и паращитовидните жлези.</li></ol><ul><li><em>Забележка:</em> Рядко (в 3-10%) съществува и <em>A. thyroidea ima</em>, излизаща директно от аортната дъга.</li></ul><li><strong>Венозен отток:</strong> Образува се богато венозно сплетение под капсулата.</li><ul><li><em>Vv. thyroideae superiores et mediae</em> се вливат в <em>v. jugularis interna</em>.</li><li><em>Vv. thyroideae inferiores</em> се вливат в <em>v. brachiocephalica</em>.</li></ul><li><strong>Клинично значение:</strong> Интензитетът на кръвотока е около 500 мл/100 гр. тъкан/мин. Това изисква изключително прецизна хемостаза при операции.</li></ul><h2>4. Инервация и важни съседни структури</h2><ul><li><strong>N. laryngeus recurrens (Възвратен ларинксов нерв):</strong> Преминава в непосредствена близост до <em>a. thyroidea inferior</em>. Инервира мускулите на ларинкса (гласните връзки). Нараняването му води до дисфония или афония.</li><li><strong>N. laryngeus superior (Горен ларинксов нерв):</strong> Преминава близо до <em>a. thyroidea superior</em>. Отговаря за инервацията на <em>m. cricothyroideus</em> (натяга гласните връзки).</li></ul><h2>5. Хистологичен строеж</h2><p>Щитовидната жлеза има уникална алвеоларна структура, която позволява складирането на големи количества хормони извън клетките.</p><ul><li><strong>Фоликули:</strong> Основната функционална единица на жлезата. Представляват затворени мехурчета.</li><li><strong>Тиреоцити (Фоликуларни клетки):</strong> Еднослоен епител, който постила фоликулите. Формата им зависи от функционалното състояние:</li><ul><li><strong>Хипофункция:</strong> Плоски клетки.</li><li><strong>Нормофункция:</strong> Кубични клетки.</li><li><strong>Хиперфункция:</strong> Високи цилиндрични клетки.</li></ul><li><strong>Колоид:</strong> Вискозна течност, изпълваща вътрешността на фоликула. Съдържа основно <strong>тиреоглобулин</strong> – белтък, в който се съхраняват щитовидните хормони.</li><li><strong>Парафоликуларни клетки (C-клетки):</strong> Разположени са между фоликулите. Те не участват в йодния метаболизъм, а секретират хормона <strong>калцитонин</strong>, който регулира калциевото ниво в кръвта (антагонист на паратхормона).</li></ul><h2>6. Физиология и хормонален синтез</h2><p>Основната роля на жлезата е производството на йодсъдържащите хормони <strong>Т4 (Тироксин)</strong> и <strong>Т3 (Трийодтиронин)</strong>.</p><h3>Етапи на хормоногенезата:</h3><ol><li><strong>Йодно захващане (Йодна помпа):</strong> Активен транспорт на йодиди от кръвта в тиреоцитите. Концентрацията на йод в жлезата е 20 до 50 пъти по-висока от тази в плазмата.</li><li><strong>Органификация на йода:</strong> Окисляване на йодидите под действие на ензима <em>тиреопероксидаза</em> и свързването им с аминокиселината тирозин в молекулата на тиреоглобулина.</li><ul><li>Образуват се монойодтирозин (MIT) и дийодтирозин (DIT).</li></ul><li><strong>Кондензация (Coupling):</strong> Свързване на йодтирозините:</li><ul><li>DIT + DIT = <strong>T4</strong> (Тироксин).</li><li>MIT + DIT = <strong>T3</strong> (Трийодтиронин).</li></ul><li><strong>Протеолиза и секреция:</strong> При нужда, тиреоглобулинът се разгражда в клетките и готовите хормони се отделят в кръвния поток.</li></ol><h2>7. Регулация на щитовидната функция</h2><p>Функцията се контролира чрез сложна система за обратна връзка (Хипоталамус – Хипофиза – Щитовидна жлеза):</p><ul><li><strong>TRH (Тиреотропин-освобождаващ хормон):</strong> Секретира се от хипоталамуса и стимулира хипофизата.</li><li><strong>TSH (Тиреостимулиращ хормон):</strong> Секретира се от предния дял на хипофизата. Това е основният регулатор – стимулира всички етапи на синтеза и секрецията на Т3 и Т4.</li><li><strong>Отрицателна обратна връзка:</strong> Високите нива на Т3 и Т4 в кръвта подтискат секрецията на TSH и TRH, за да се поддържа хомеостаза.</li></ul><h2>8. Биологично действие на хормоните</h2><p>Щитовидните хормони влияят на почти всяка клетка в тялото:</p><ul><li><strong>Метаболизъм:</strong> Повишават основната обмяна и кислородната консумация. Регулират обмяната на белтъци, мазнини и въглехидрати.</li><li><strong>Терморегулация:</strong> Увеличават производството на топлина в тялото.</li><li><strong>Растеж и развитие:</strong> Критично важни за физическия растеж и съзряването на централната нервна система (особено в ембрионалния период и ранното детство).</li><li><strong>Сърдечно-съдова система:</strong> Повишават сърдечната честота и силата на съкращенията.</li></ul><h2>9. Класификация на заболяванията на щитовидната жлеза</h2><p>Заболяванията се класифицират според техния характер, функционално състояние и разпространение:</p><ul><li><strong>Вродени аномалии:</strong> Аплазия, хипоплазия, ектопия (Lingua thyroidea), персистиращ Ductus thyroglossus.</li><li><strong>Гуша (Струма):</strong> Нетуморно увеличение на жлезата (ендемична или спорадична).</li><li><strong>Тиреоидити (Възпаления):</strong> </li><ul><li>Остри (гнойни и негнойни).</li><li>Подостри (на De Quervain).</li><li>Хронични (на Hashimoto, на Riedel).</li></ul><li><strong>Тиреотоксикоза:</strong> Базедова болест (Morbus Basedow) и токсичен аденом.</li><li><strong>Тумори:</strong></li><ul><li>Доброкачествени (аденоми).</li><li>Злокачествени (карциноми – папиларен, фоликуларен, медуларен, анапластичен).</li></ul></ul><hr><h2>10. Струма (Гуша)</h2><h3>Дефиниция</h3><p>Струмата (Struma) представлява всяко невъзпалително и нетуморно увеличение на щитовидната жлеза. Тя не е самостоятелна нозологична единица, а клиничен симптом на различни патологични състояния.</p><h3>Етиология и патогенеза</h3><p>Основният механизъм за развитие на струма е компенсаторната хиперплазия на жлезата.</p><ul><li><strong>Йоден дефицит:</strong> Най-честата причина в световен мащаб. Недостатъчният прием на йод води до ниско производство на Т3 и Т4.</li><li><strong>Механизъм на обратната връзка:</strong> Ниските нива на тиреоидни хормони стимулират предния дял на хипофизата да секретира по-големи количества <strong>TSH</strong>.</li><li><strong>Хипертрофия:</strong> Хронично високите нива на TSH водят до разрастване на жлезната тъкан с цел да се \"улови\" повече йод и да се компенсира дефицитът.</li><li><strong>Струмигенни фактори:</strong> Вещества (тиоцианати, перхлорати), съдържащи се в някои храни (зеле, соя, ряпа) или медикаменти, които блокират синтеза на хормони.</li></ul><h3>Класификация на струмата</h3><p><strong>А. Според епидемиологията:</strong></p><ol><li><strong>Ендемична струма:</strong> Поразява над 10% от населението в определени райони (планински райони с бедна на йод почва и вода).</li><li><strong>Спорадична струма:</strong> Среща се в неендемични райони; често е резултат от генетични ензимни дефекти или индивидуални нужди (пубертет, бременност).</li></ol><p><strong>Б. Според морфологията (Макроскопски строеж):</strong></p><ul><li><strong>Struma diffusa (Дифузна):</strong> Жлезата е равномерно увеличена, гладка и мека. Често се среща при млади хора.</li><li><strong>Struma nodosa (Възлова):</strong> В жлезата се палпират един или повече възли. Възлите могат да бъдат \"<strong>топли</strong>\" (функциониращи) или \"<strong>студени</strong>\" (нефункциониращи).</li><li><strong>Struma mixta (Смесена):</strong> Комбинация от общо увеличение на паренхима и наличие на възли.</li></ul><p><strong>В. Според локализацията:</strong></p><ul><li><strong>Шийна (обичайна):</strong> Разположена на типичното място на шията.</li><li><strong>Задгръдна (Ендоторакална):</strong> Развива се надолу зад стернума. Може да предизвика компресия на медиастиналните органи.</li><li><strong>Ектопична:</strong> Развива се от остатъци на щитовидна тъкан по хода на ембрионалния път (например под езика).</li></ul><p><strong>Г. Според функционалното състояние:</strong></p><ul><li><strong>Еутиреоидна:</strong> Нормално ниво на хормоните (най-често).</li><li><strong>Хипотиреоидна:</strong> Намалена функция.</li><li><strong>Хипертиреоидна (Токсична):</strong> Повишена продукция на хормони (напр. токсичен аденом).</li></ul><h3>Клинични степени на увеличение (СЗО)</h3><ol><li><strong>Степен 0:</strong> Няма видима или палпируема гуша.</li><li><strong>Степен I:</strong> Гушата се палпира, но не се вижда при нормално положение на шията.</li><ul><li><em>Ia:</em> Палпира се, но не се вижда дори при изпъната назад шия.</li><li><em>Ib:</em> Вижда се само при максимално изпъната назад шия.</li></ul><li><strong>Степен II:</strong> Гушата е видима при нормално положение на шията.</li><li><strong>Степен III:</strong> Голяма гуша, видима от разстояние, водеща до деформация на шията.</li></ol><h3>Клинична картина и усложнения</h3><p>Клиничната изява на заболяването зависи пряко от морфологичните характеристики на жлезата (размер, локализация) и нейната функционална активност.</p><p><strong>Основни клинични прояви</strong></p><ul><li><strong>Козметичен дефект:</strong> Видима деформация в предната част на шията, която може да варира от дискретно подуване до масивна туморна формация.</li><li><strong>Функционални нарушения:</strong> Промени в хормоналните нива, водещи до:</li><ul><li><strong>Хипертиреоидизъм:</strong> Сърцебиене, нервност, тремор, отслабване на тегло.</li><li><strong>Хипотиреоидизъм:</strong> Лесна уморяемост, сънливост, забавен пулс, отоци.</li></ul></ul><p><strong>Механични усложнения (Компресионен синдром)</strong></p><ul><li><strong>Компресия на трахеята:</strong> Предизвиква <strong>диспнея</strong>, <strong>стридор</strong>&nbsp;и в тежки случаи – омекване на трахеалните хрущяли (<strong>трахеомалация</strong>).</li><li><strong>Компресия на хранопровода:</strong> Води до затруднено и болезнено гълтане (<strong>дисфагия</strong>).</li><li><strong>Притискане на нерви:</strong> Най-често се засяга <em>n. laryngeus recurrens</em>, което причинява <strong>дисфония</strong>&nbsp;или <strong>афония</strong>.</li><li><strong>Синдром на горната празна вена:</strong> Притискане на големите венозни съдове, което води до оток на лицето и шията и наличие на разширени вени по гръдната стена.</li></ul><p><strong>Структурни и функционални усложнения</strong></p><ul><li><strong>Възпаление (Струмит):</strong> Вторичен възпалителен процес в предварително променена щитовидна тъкан.</li><li><strong>Кръвоизлив във възел:</strong> Внезапно и болезнено нарастване на възел, често съпроводено с чувство на силно напрежение.</li><li><strong>Базедовификация:</strong> Трансформация на еутиреоидната струма в токсична (хиперфункция) – състояние, известно като <strong>вторична токсична гуша</strong>.</li><li><strong>Малигнизация:</strong> Злокачествено израждане на дългогодишна възлова струма (рискът е особено висок при наличие на т.нар. „студени“ възли).</li></ul><h3>Диагностичен подход</h3><ol><li><strong>Палпация:</strong> Определяне на консистенция, подвижност и наличие на възли.</li><li><strong>Ехография (Ултразвук):</strong> Най-точният метод за определяне на обема на жлезата и структурата на възлите.</li><li><strong>Лабораторни изследвания:</strong> Измерване на нивата на <strong>TSH, fT4 и fT3</strong> в кръвта.</li><li><strong>Сцинтиграфия:</strong> Използва се за оценка на функционалната активност на възлите (\"топли\" срещу \"студени\").</li><li><strong>Тънкоиглена аспирационна биопсия (ТАБ):</strong> Задължителна при наличие на подозрителни възли за изключване на карцином.</li><li><p><strong>КТ на шия</strong>.</p><br></li></ol><h3>Диференциална диагноза</h3><p>При наличие на увеличение (възел) в щитовидната жлеза е критично да се изключат следните заболявания:</p><ul><li><strong>Карцином на щитовидната жлеза:</strong> Най-важната диференциална диагноза. Подозрителни са \"студените\", плътни и бързо нарастващи възли.</li><li><strong>Тиреоидити:</strong> <em> </em></li><ul><li><i>Подостър тиреоидит (на De Quervain)</i>: Протича с болка в областта на жлезата и повишена температура.</li><li><em>Хроничен тиреоидит (на Hashimoto):</em> Жлезата е с характерна плътно-еластична консистенция и неравна повърхност.</li></ul><li><strong>Аденом (Доброкачествен тумор):</strong> Обикновено е единичен, добре капсулиран възел.</li><li><strong>Кисти на щитовидната жлеза:</strong> Ехографски се доказват като гладкостенни кухини, изпълнени с течност.</li><li><strong>Лимфоми и метастази:</strong> По-редки случаи на злокачествени процеси.</li></ul><h3>Лечение на струмата</h3><p>Изборът на лечебен метод зависи от вида на струмата, нейния размер и функционално състояние.</p><h4>А. Консервативно лечение</h4><p>Прилага се основно при дифузни еутиреоидни струми в начален стадий:</p><ul><li><strong>Йодна профилактика и терапия:</strong> Прием на калиев йодид (особено при ендемична гуша).</li><li><strong>Супресивна терапия с L-тироксин:</strong> Цели се подтискане на секрецията на TSH от хипофизата, което води до намаляване размера на жлезата.</li></ul><h4>Б. Хирургично лечение (Оперативно)</h4><p>Това е водещият метод при възлови форми и компресионен синдром.</p><p><strong>Показания за операция:</strong></p><ol><li><strong>Съмнение за злокачественост:</strong> Всеки възел, който буди съмнение за карцином.</li><li><strong>Механична компресия:</strong> Притискане на трахеята (задух) или хранопровода (трудно гълтане).</li><li><strong>Задгръдна (медиастинална) локализация:</strong> Поради риск от внезапно задушаване.</li><li><strong>Токсична струма:</strong> Когато медикаментозното лечение не дава резултат.</li><li><strong>Козметичен дефект:</strong> При много големи размери, деформиращи шията.</li></ol><p><strong>Основни видове операции:</strong></p><ul><li><strong>Резекция на жлезата:</strong> Отстраняване на част от лоба.</li><li><strong>Лобектомия:</strong> Отстраняване на един цял лоб.</li><li><strong>Тиреоидектомия (Тотална):</strong> Пълно отстраняване на щитовидната жлеза (задължително при карцином).</li></ul><h4>В. Лечение с радиоактивен йод (131J)</h4><ul><li>Прилага се предимно при токсични форми (хипертиреоидизъм) или при възрастни пациенти, при които операцията е високорискова. Радиоактивният йод разрушава хиперактивната тъкан \"отвътре\".</li></ul><h3>Специфични следоперативни усложнения</h3><p>Хирургичното лечение на щитовидната жлеза крие специфични рискове поради сложната анатомия на шията:</p><ol><li><strong>Хипопаратиреоидизъм:</strong></li><ul><li><strong>Причина:</strong> Случайно отстраняване или увреждане на кръвоснабдяването на паращитовидните жлези по време на операция.</li><li><strong>Симптоми:</strong> Рязко спадане на калция в кръвта, което води до мускулни крампи и тетания.</li></ul><li><strong>Увреждане на възвратния ларинксов нерв (n. laryngeus recurrens):</strong></li><ul><li><strong>Едностранно:</strong> Води до трайна дисфония.</li><li><strong>Двустранно:</strong> Изключително тежко усложнение, водещо до затваряне на гласната цепка и остра дихателна недостатъчност, често налагаща трахеостомия.</li></ul><li><strong>Следоперативен кръвоизлив:</strong></li><ul><li>Тъй като жлезата е силно кръвоснабдена, образуването на хематом може бързо да притисне трахеята и да причини задушаване.</li></ul><li><strong>Тиреотоксична криза:</strong></li><ul><li>Рядко, но жизнезастрашаващо състояние, възникващо при операция на пациент с некомпенсирана хиперфункция (изхвърляне на голямо количество хормони в кръвта).</li></ul></ol><hr><h2>11. Тиреотоксикоза (Хипертиреоидизъм)</h2><h3>Етиологична класификация и патогенеза</h3><p>Тиреотоксикозата не е единна болест, а състояние на хиперметаболизъм. Основните форми се различават по своя механизъм:</p><ul><li><strong>Базедова болест (Graves' disease):</strong> Автоимунен процес, при който се синтезират <strong>TSH-рецепторни антитела (TRAb)</strong>. Те имитират действието на TSH и принуждават жлезата да работи непрекъснато, независимо от нуждите на организма.</li><li><strong>Токсичен аденом (Болест на Плъмър):</strong> Доброкачествен тумор (възел), който придобива функционална автономност. Той произвежда хормони в излишък, докато останалата част от жлезата често атрофира поради подтиснатия TSH.</li><li><strong>Токсична мултинодозна струма:</strong> Характерна за по-възрастни пациенти с дългогодишна гуша. В нея се развиват множество огнища (възли), които започват да свръхпродуцират хормони.</li><li><strong>Йод-индуцирана тиреотоксикоза (Jod-Basedow):</strong> Предизвикана от прием на големи дози йод (напр. контрастни вещества или лекарства като Амиодарон).</li></ul><h3>Клинична картина</h3><h4>А. Невро-вегетативна система</h4><ul><li><strong>Психика:</strong> Свръхвъзбудимост, раздразнителност, пристъпи на плач, панически атаки.</li><li><strong>Тремор:</strong> Фин, ритмичен тремор на пръстите на разперените ръце и езика.</li><li><strong>Мускулна слабост:</strong> Т.нар. \"тиреотоксична миопатия\" – затруднение при изкачване на стълби или ставане от стол.</li></ul><h4>Б. Сърдечно-съдова система (Тиреотоксично сърце)</h4><p>Хормоните директно повишават чувствителността на сърцето към адреналин:</p><ul><li><strong>Тахикардия:</strong> Ускорен пулс (над 100 уд./мин.) в покой и по време на сън.</li><li><strong>Предсърдно мъждене:</strong> Често усложнение при възрастни пациенти, което крие риск от тромбоемболии.</li><li><strong>Високо артериално налягане:</strong> Повишено систолно и нормално или ниско диастолно налягане.</li></ul><h4>В. Очни симптоми (Ендокринна офталмопатия)</h4><p>Дължат се на автоимунно възпаление и оток на мастната тъкан и мускулите зад окото:</p><ul><li><strong>Екзофталм:</strong> Изпъкване на очите (едностранно или двустранно).</li><li><strong>Симптом на Dalrymple:</strong> Разширена очна цепка (\"втренчен поглед\").</li><li><strong>Симптом на Joffroy:</strong> Липса на сбръчкване на челото при поглед нагоре.</li></ul><h3>Диагностика</h3><ol><li><strong>Хормонален профил:</strong></li><ul><li><strong>TSH:</strong> Почти 0 mIU/l (най-чувствителният маркер).</li><li><strong>fT4 и fT3:</strong> Силно повишени.</li></ul><li><strong>Имунологични изследвания:</strong> Изследване на <strong>ТRАb</strong> (позитивни при Базедова болест).</li><li><strong>Ехография с Доплер:</strong> Установява се \"тиреоиден ад\" (thyroid inferno) – екстремно засилено кръвоснабдяване на жлезата.</li><li><strong>Радиоизотопно изследване (Сцинтиграфия):</strong> Позволява разграничаване на дифузна форма (Базедова) от \"горещ\" възел (аденом).</li></ol><h3>Лечебни стратегии</h3><h4>Медикаментозно лечение (Тиреостатици)</h4><ul><li><strong>Препарати:</strong> Thiamazole (Тирозол/Метизол) или Propylthiouracil.</li><li><strong>Действие:</strong> Блокират вграждането на йод в тиреоглобулина.</li><li><strong>Продължителност:</strong> Обикновено 12–18 месеца при Базедова болест с надежда за ремисия.</li></ul><h4>Радиойодтерапия (131J)</h4><ul><li>Пациентът поглъща капсула с радиоактивен йод, който се натрупва само в щитовидната жлеза и я разрушава локално.</li><li><strong>Метод на избор</strong> при токсичен аденом и рецидиви след медикаментозно лечение.</li></ul><h4>Хирургично лечение (Тиреоидектомия)</h4><ul><li><strong>Показания:</strong> Големи струми с компресия, неуспех от другите методи, бременност (при невъзможност за контрол), съмнение за рак.</li><li><strong>Подготовка:</strong> Пациентът задължително трябва да бъде приведен в <strong>еутиреоидно състояние</strong> (нормални хормони) преди операцията, за да се избегне тиреотоксична криза.</li></ul><h3>Тиреотоксична криза</h3><p>Най-тежкото, жизнезастрашаващо усложнение.</p><ul><li><strong>Причини:</strong> Инфекция, травма или операция при нелекувана тиреотоксикоза.</li><li><strong>Симптоми:</strong> Екстремна тахикардия, много висока температура (над 40°C), психоза, кома и сърдечна недостатъчност.</li><li><strong>Лечение:</strong> Спешна реанимация, високи дози тиреостатици, бета-блокери и кортикостероиди.</li></ul><h3>Усложнения при хирургично лечение</h3><h4>Интраоперативни (По време на операцията)</h4><ul><li><strong>Кръвоизлив:</strong> Поради силното кръвоснабдяване на жлезата.</li><li><strong>Нараняване на n. laryngeus recurrens (възвратен нерв):</strong></li><ul><li><em>Едностранно:</em> Дисфония.</li><li><em>Двустранно:</em> Остър задух (изисква спешна трахеостомия).</li></ul><li><strong>Нараняване на n. laryngeus superior:</strong> Промяна в тембъра и силата на гласа.</li></ul><h4>Ранни следоперативни (до 48 часа)</h4><ul><li><strong>Следоперативен хематом:</strong> Натрупване на кръв, което притиска трахеята и води до задушаване. Налага спешно отваряне на раната.</li><li><strong>Хипопаратиреоидизъм (Хипокалциемия):</strong> При увреждане на паращитовидните жлези.</li><ul><li><em>Симптоми:</em> Изтръпване на пръстите и устата, мускулни крампи.</li><li><em>Тестове:</em> Положителни признаци на Хвостек и Трусо.</li></ul><li><strong>Тиреотоксична криза:</strong> Опасно състояние при пациенти, които не са били правилно подготвени с лекарства преди операцията.</li></ul><h4>Късни усложнения</h4><ul><li><strong>Трахеомалация:</strong> Сплескване на трахеята след премахване на много голяма гуша.</li><li><strong>Постоянен хипотиреоидизъм:</strong> Налага доживотен прием на L-тироксин (след пълно отстраняване на жлезата).</li><li><strong>Рецидив:</strong> Повторно появяване на заболяването при непълна операция.</li><li><strong>Проблеми с белега:</strong> Образуване на келоиди (груба тъкан) на шията.</li></ul><hr><h2>13. Доброкачествени тумори на щитовидната жлеза</h2><p>Доброкачествените тумори са най-честите неоплазми на щитовидната жлеза. Те произхождат от фоликуларния епител и се характеризират с бавен растеж и липса на метастазиране.</p><h3>Аденом на щитовидната жлеза (Adenoma glandulae thyroideae)</h3><p>Аденомът е най-разпространеният доброкачествен тумор. Обикновено се представя като единичен (солитарен) възел.</p><h4>Основни характеристики:</h4><ul><li><strong>Капсула:</strong> Аденомът е напълно обвит от добре изразена фиброзна капсула, която го отделя от околния паренхим.</li><li><strong>Консистенция:</strong> Плътно-еластична, с ясни и гладки граници при палпация.</li><li><strong>Подвижност:</strong> Подвижен е спрямо околните тъкани и се движи заедно с жлезата при гълтане.</li></ul><h4>Хистологични варианти:</h4><ol><li><strong>Фоликуларен аденом:</strong> Най-честият тип. Изграден е от малки фоликули.</li><li><strong>Папиларен аденом:</strong> Среща се по-рядко; има специфична папиларна структура.</li><li><strong>Хюртле-клетъчен аденом (Оксифилен):</strong> Изграден от големи, еозинофилни клетки (клетки на Askanazy). Има малко по-висок риск от злокачествена трансформация.</li></ol><h3>Клинична картина</h3><p>В повечето случаи доброкачествените тумори протичат безсимптомно и се откриват случайно.</p><ul><li><strong>Палпируем възел:</strong> Често е единственият симптом.</li><li><strong>Липса на болка:</strong> Обикновено са безболезнени, освен ако не настъпи кръвоизлив в тумора.</li><li><strong>Компресия (рядко):</strong> При много големи размери могат да притиснат трахеята или хранопровода.</li><li><strong>Функция:</strong> Повечето аденоми са „студени“, но съществува и <strong>токсичен аденом</strong>, който води до хипертиреоидизъм.</li></ul><h3>Диагностичен подход</h3><p>Целта е да се разграничи доброкачественият аденом от рак на щитовидната жлеза.</p><ul><li><strong>Ехография:</strong> Основен метод. Аденомите са с правилна форма, ясни очертания и често имат „хало“ (светъл пръстен) около капсулата.</li><li><strong>Тънкоиглена аспирационна биопсия (ТАБ):</strong> <strong>Най-важният метод.</strong> Позволява вземане на клетки за цитологично изследване.</li><li><strong>Сцинтиграфия:</strong> Определя функционалната активност. </li><ul><li><em>„Топли“/„Горещи“ възли</em> – рядко са злокачествени.</li><li><em>„Студени“ възли</em> – изискват повишено внимание.</li></ul></ul><h3>Диференциална диагноза</h3><p>Аденомът трябва да се разграничи от:</p><ul><li>Възлова форма на ендемична или спорадична струма.</li><li>Кисти на щитовидната жлеза.</li><li>Карцином на щитовидната жлеза.</li><li>Хроничен тиреоидит на Хашимото (псевдовъзли).</li></ul><h3>Лечение</h3><p>Поведението зависи от резултатите от биопсията и размера на тумора.</p><ul><li><strong>Консервативно (наблюдение):</strong> При малки, доказано доброкачествени аденоми без функционални нарушения се провежда периодично ехографско проследяване.</li><li><strong>Хирургично лечение:</strong></li><ul><li><strong>Показания:</strong> Съмнение за злокачественост (несигурна цитология), големи размери с компресия, токсичен аденом или козметичен дефект.</li><li><strong>Обем на операцията:</strong> Обикновено се извършва <strong>енуклеация</strong> (изваждане на възела с капсулата) или <strong>резекция на лоба (лобектомия)</strong>, в който е разположен туморът.</li></ul></ul><hr><h2>14. Карцином на щитовидната жлеза (Злокачествени тумори)</h2><p>Карциномът на щитовидната жлеза е най-честото злокачествено заболяване на органите на ендокринната система. Характеризира се с голямо хистологично разнообразие и различна степен на агресивност.</p><h3>Класификация по СЗО (Хистологични типове)</h3><h4>А. Диференцирани карциноми (с добра прогноза)</h4><ul><li><strong>Папиларен карцином (70-80%):</strong> </li><ul><li>Най-честият тип.</li><li>Среща се във всички възрасти, включително при деца.</li><li>Метастазира предимно по <strong>лимфен път</strong> в шийните лимфни възли.</li><li>Развива се бавно и има отлична прогноза при адекватно лечение.</li></ul><li><strong>Фоликуларен карцином (10-15%):</strong> </li><ul><li>Среща се по-често в ендемични райони (йоден дефицит).</li><li>Метастазира предимно по <strong>кръвен път</strong> (бели дробове, кости).</li><li>По-агресивен от папиларния.</li></ul></ul><h4>Б. Медуларен карцином (5-10%)</h4><ul><li>Произхожда от <strong>С-клетките</strong> (парафоликуларните клетки), които секретират <strong>калцитонин</strong>.</li><li>Може да бъде спорадичен или наследствен.</li><li>Метастазира както по лимфен, така и по кръвен път.</li></ul><h4>В. Анапластичен карцином (под 5%)</h4><ul><li>Един от най-агресивните тумори в човешката патология.</li><li>Засяга предимно възрастни хора (60-70г.).</li><li>Бърз инфилтративен растеж, водещ до задушаване. Прогнозата е изключително тежка.</li></ul><h3>Клинична картина</h3><p>Злокачествените тумори често започват безсимптомно. Подозрителни признаци са:</p><ul><li><strong>Солитарен (единичен) възел:</strong> Плътен, с неясни граници, фиксиран към околните тъкани.</li><li><strong>Бърз растеж:</strong> Рязко увеличаване на обема на жлезата или вече съществуващ възел.</li><li><strong>Лимфаденопатия:</strong> Увеличени и плътни лимфни възли на шията.</li><li><strong>Признаци на инвазия:</strong></li><ul><li><em>Дисфония:</em> Поради засягане на n. laryngeus recurrens.</li><li><em>Дисфагия.</em></li><li><em>Диспнея.</em></li></ul></ul><h3>Диагностичен алгоритъм</h3><ol><li><strong>Ехография:</strong> Визуализира белези на малигненост (хипоехогенност, микрокалцификати, неясни граници, засилен централен кръвоток).</li><li><strong>Тънкоиглена аспирационна биопсия (ТАБ):</strong> Златен стандарт за предоперативна диагноза.</li><li><strong>Лабораторни изследвания:</strong> </li><ul><li><strong>Тиреоглобулин (Tg):</strong> Маркер за проследяване след операция (само при диференцирани карциноми).</li><li><strong>Калцитонин:</strong> Специфичен маркер за Медуларен карцином.</li></ul><li><strong>Сцинтиграфия:</strong> Карциномите обикновено се представят като <strong>\"студени\" възли</strong> (не натрупват изотоп).</li></ol><h3>Лечение</h3><h4>Хирургично лечение (Основен метод)</h4><ul><li><strong>Тотална тиреоидектомия:</strong> Пълно отстраняване на жлезата. Това е стандартът при доказан карцином.</li><li><strong>Шийна лимфна дисекция:</strong> Отстраняване на засегнатите лимфни възли на шията.</li></ul><h4>Постоперативно лечение и проследяване</h4><ul><li><strong>Терапия с радиоактивен йод (131J):</strong> Прилага се след операция при диференцирани карциноми за унищожаване на остатъчни микрометастази. (Не е ефективна при медуларен и анапластичен рак).</li><li><strong>Супресивна терапия с L-тироксин:</strong> Приемат се високи дози хормон, за да се подтисне TSH, който иначе би стимулирал растежа на евентуални туморни клетки.</li><li><strong>Периодично проследяване:</strong> Чрез ехография и изследване на туморни маркери (Тиреоглобулин или Калцитонин).</li></ul><hr><br><br><style></p><p>    body { </p><p>      font-family: \"Open Sans\", Arial, sans-serif; </p><p>      max-width: 1200px; </p><p>      margin: 2rem auto; </p><p>      padding: 0 1rem; </p><p>      line-height: 1.6; </p><p>      color: #1f2937; </p><p>    }</p><p>    h1 { </p><p>      font-weight: 600; </p><p>      font-size: 1.5em;</p><p>      margin-top: 1.5em;</p><p>      margin-bottom: 0.5em;</p><p>      color: #3a5a40;</p><p>      border-bottom: 2px dashed #a3b18a;</p><p>      padding-bottom: 5px;</p><p>    }</p><p>    p { </p><p>      margin: 0.7em 0 1.5em 0; </p><p>      white-space: pre-wrap;</p><p>    }</p><p>    @media (max-width: 768px) {</p><p>      body { font-size: 16px; }</p><p>      h1 { font-size: 1.3em; }</p><p>    }</p><p>  </style>\n<script src=\"https://cdn.jsdelivr.net/npm/katex@0.16.4/dist/katex.min.js\"></script>\n<script src=\"https://cdn.jsdelivr.net/npm/katex@0.16.4/dist/contrib/auto-render.min.js\"></script>\n<script>\nrenderMathInElement(document.body, {\n  delimiters: [\n    {left: '$$', right: '$$', display: true},\n    {left: '$', right: '$', display: false},\n    {left: '\\\\[', right: '\\\\]', display: true},\n    {left: '\\\\(', right: '\\\\)', display: false}\n  ],\n  throwOnError: false\n});\n</script>\n</body>\n</html>","files/Хирургически болести/Гръдна хирургия/3-msg-Възпалителни заболявания на белия дроб.html":"<!DOCTYPE html>\n<html lang=\"bg\">\n<head>\n  <meta charset=\"UTF-8\">\n  <meta name=\"viewport\" content=\"width=device-width, initial-scale=1.0\">\n  <title>Абсцес на белия дроб</title>\n  <link rel=\"stylesheet\" href=\"https://cdn.jsdelivr.net/npm/katex@0.16.4/dist/katex.min.css\">\n  <style>\n    body { \n      font-family: \"Open Sans\", Arial, sans-serif; \n      max-width: 1550px; \n      margin: 0.5rem auto; \n      padding: 0 1rem; \n      line-height: 1.6; \n      color: #1f2937; \n    }\n    h1, h2, h3, h4 { \n      font-weight: 600; \n      margin-top: 0.7em;\n      margin-bottom: 0;\n      color: #588157;\n    }\n    h1 { font-size: 1.65em; }\n    h2 { font-size: 1.3em; }\n    h3 { font-size: 1.1em; margin-bottom: 0; }\n    h4 { font-size: 1.05em; margin-bottom: 0; }\n    h1 + h2, h1 + h3, h1 + h4, h2 + h3, h2 + h4, h3 + h4 { margin-top: 0.1em; }\n    p { \n      margin: 0.3em 0; \n      white-space: pre-wrap;\n    }\n    hr {\n      margin: 0.45em 0 0.2em;\n    }\n    hr + h1,\n    hr + h2,\n    hr + h3,\n    hr + h4 {\n      margin-top: 0.2em;\n    }\n    hr + p,\n    hr + ul,\n    hr + ol,\n    hr + blockquote,\n    hr + pre,\n    hr + table {\n      margin-top: 0.08em;\n    }\n    p + ul, p + ol { margin-top: 0.2em; }\n    h1 + p, h2 + p, h3 + p, h4 + p,\n    h1 + ul, h2 + ul, h3 + ul, h4 + ul,\n    h1 + ol, h2 + ol, h3 + ol, h4 + ol { \n      margin-top: 0; \n    }\n    ul, ol { \n      margin: 0.2em 0; \n      padding-left: 1.5em; \n      list-style-position: outside;\n    }\n    li { margin: 0.2em 0; }\n    li p {\n      margin: 0;\n      padding: 0;\n      display: inline;\n    }\n    li > ul, li > ol {\n      margin: 0.15em 0 0 0;\n      padding-left: 1.5em;\n    }\n    ul ul, ul ol, ol ul, ol ol {\n      margin-top: 0.1em;\n      padding-left: 1.5em;\n    }\n    ul ul { list-style-type: circle; }\n    ul ul ul { list-style-type: square; }\n    strong { font-weight: 600; }\n    em { font-style: italic; }\n    code { \n      background: rgba(218, 215, 205, 0.3); \n      padding: 2px 6px; \n      border-radius: 3px; \n      font-family: \"Courier New\", monospace; \n      font-size: 0.9em; \n    }\n    pre {\n      background: rgba(255, 255, 255, 0.5);\n      padding: 12px;\n      border-radius: 4px;\n      overflow-x: auto;\n      margin: 0.5em 0;\n      font-family: \"Courier New\", monospace;\n    }\n    pre code {\n      background: none;\n      padding: 0;\n    }\n    blockquote {\n      border-left: 3px solid #588157;\n      padding-left: 1em;\n      margin: 0.5em 0;\n      font-style: italic;\n      color: #166534;\n    }\n    table { \n      border-collapse: collapse; \n      margin: 0.75em 0; \n      width: 100%; \n      table-layout: auto;\n    }\n    th, td { \n      border: 1px solid rgba(2, 2, 2, 0.2);\n      padding: 6px 10px; \n      text-align: left; \n      vertical-align: top;\n      height: 24px;\n      line-height: 1.2;\n    }\n    thead th { \n      background: rgba(88, 129, 87, 0.13); \n      font-weight: 600; \n    }\n    tbody tr:nth-child(odd) { \n      background: rgba(88, 129, 87, 0.06); \n    }\n    /* Image alignment rules for exported content and md-viewer */\n    img[data-align=\"left\"] {\n      display: block;\n      margin: 8px auto 8px 0;\n    }\n    img[data-align=\"center\"] {\n      display: block;\n      margin: 8px auto;\n    }\n    img[data-align=\"right\"] {\n      display: block;\n      margin: 8px 0 8px auto;\n    }\n    .audio-link-inline {\n      display: inline-flex;\n      align-items: center;\n      gap: 8px;\n      margin: 0.2em 0;\n      max-width: 100%;\n      vertical-align: middle;\n    }\n    .audio-link-icon {\n      width: 28px;\n      height: 28px;\n      border: 1px solid #588157;\n      border-radius: 999px;\n      background: #f0f7f0;\n      color: #2f5d50;\n      cursor: pointer;\n      font-size: 14px;\n      line-height: 1;\n      display: inline-flex;\n      align-items: center;\n      justify-content: center;\n      flex: 0 0 auto;\n    }\n    .audio-link-inline audio {\n      position: absolute;\n      width: 1px;\n      height: 1px;\n      opacity: 0;\n      overflow: hidden;\n      pointer-events: none;\n    }\n    .audio-link-icon img {\n      width: 14px;\n      height: 14px;\n      object-fit: contain;\n      pointer-events: none;\n    }\n    a {\n      color: inherit; /* Changed to inherit */\n      text-decoration: underline;\n    }\n    a:hover {\n      color: #74b673;\n    }\n    /* Keep <p> tags inside list items on same line (as they appear in editor) */\n    li p {\n      margin: 0 !important;\n      padding: 0 !important;\n      display: inline !important;\n    }\n    /* Prevent nested list paragraph issues */\n    li > ul,\n    li > ol {\n      margin: 0.15em 0 0 0;\n      padding-left: 1.5em;\n    }\n    /* Ensure list structure is clean */\n    ul ul, ul ol,\n    ol ul, ol ol {\n      margin-top: 0.1em;\n      padding-left: 1.5em;\n    }\n    @media (max-width: 768px) {\n      body {\n        margin: 0.5rem 0;\n        padding: 0 0.5rem;\n        font-size: 16px;\n      }\n      h1 { font-size: 1.65em; }\n      h2 { font-size: 1.3em; }\n      h3 { font-size: 1.1em; }\n      p { margin: 0.3em 0; }\n      ul, ol { padding-left: 1.5em; }\n      li { margin: 0.2em 0; }\n      table { font-size: 0.9em; }\n      th, td { padding: 6px 10px; }\n    }\n    .editor-note {\n      text-decoration: underline dotted #a3b18a;\n      text-decoration-thickness: 2px;\n      text-underline-offset: 2px;\n      text-decoration-skip-ink: none;\n      cursor: help;\n      position: relative;\n    }\n    .note-tooltip {\n      display: none;\n      position: absolute;\n      background-color: #f0f7f0;\n      color: #1f2937;\n      border: 1px solid #588157;\n      border-radius: 4px;\n      padding: 8px 12px;\n      width: fit-content;\n      max-width: min(700px, calc(100vw - 20px));\n      max-height: calc(100vh - 20px);\n      overflow: auto;\n      box-sizing: border-box;\n      box-shadow: 0 2px 8px rgba(0,0,0,0.2);\n      z-index: 10000;\n      font-size: 0.9em;\n      line-height: 1.4;\n      word-wrap: break-word;\n    }\n    .note-tooltip ul, .note-tooltip ol {\n      margin: 0 !important;\n      padding-left: 20px !important;\n    }\n    .note-tooltip li {\n      margin: 0 0 0.1em 0 !important;\n      padding: 0 !important;\n      line-height: 1.2 !important;\n    }\n    .note-tooltip li:last-child {\n      margin-bottom: 0 !important;\n    }\n  </style>\n  <script>\n    document.addEventListener('DOMContentLoaded', function() {\n      const tooltip = document.createElement('div');\n      tooltip.className = 'note-tooltip';\n      document.body.appendChild(tooltip);\n\n      function parseNoteMarkdown(text) {\n        if (!text) return '';\n        \n        let lines = text.split('\\n');\n        let html = [];\n        let stack = [];\n        \n        for (let i = 0; i < lines.length; i++) {\n          let line = lines[i];\n          \n          let indentMatch = line.match(/^(\\s*)/);\n          let indent = indentMatch ? indentMatch[1].length : 0;\n          let content = line.trim();\n          \n          let isUl = /^[-*]\\s+(.+)/.test(content);\n          let isOl = /^\\d+\\.\\s+(.+)/.test(content);\n          \n          if (isUl || isOl) {\n            let listType = isUl ? 'ul' : 'ol';\n            let match = isUl ? content.match(/^[-*]\\s+(.+)/) : content.match(/^\\d+\\.\\s+(.+)/);\n            let itemText = match[1];\n            \n            if (stack.length === 0) {\n              stack.push({ type: listType, indent: indent });\n              html.push('<' + listType + '>');\n            } else {\n              let last = stack[stack.length - 1];\n              \n              if (indent > last.indent) {\n                stack.push({ type: listType, indent: indent });\n                html.push('<' + listType + '>');\n              } else if (indent < last.indent) {\n                while (stack.length > 0 && stack[stack.length - 1].indent > indent) {\n                  let closed = stack.pop();\n                  html.push('</' + closed.type + '>');\n                }\n                if (stack.length === 0 || stack[stack.length - 1].indent !== indent) {\n                   stack.push({ type: listType, indent: indent });\n                   html.push('<' + listType + '>');\n                } else if (stack[stack.length - 1].type !== listType) {\n                   let closed = stack.pop();\n                   html.push('</' + closed.type + '>');\n                   stack.push({ type: listType, indent: indent });\n                   html.push('<' + listType + '>');\n                }\n              } else {\n                if (last.type !== listType) {\n                  let closed = stack.pop();\n                  html.push('</' + closed.type + '>');\n                  stack.push({ type: listType, indent: indent });\n                  html.push('<' + listType + '>');\n                }\n              }\n            }\n            html.push('<li>' + itemText + '</li>');\n          } else {\n            if (content !== '') {\n               while (stack.length > 0) {\n                 let closed = stack.pop();\n                 html.push('</' + closed.type + '>');\n               }\n            }\n            if (/^#{1,4}\\s+/.test(content)) {\n              const headingMatch = content.match(/^(#{1,4})\\s+(.+)$/);\n              if (headingMatch) {\n                const level = headingMatch[1].length;\n                html.push('<h' + level + '>' + headingMatch[2] + '</h' + level + '>');\n              }\n            } else if (content) {\n              html.push(content + '<br>');\n            } else {\n              html.push('<br>');\n            }\n          }\n        }\n        \n        while (stack.length > 0) {\n          let closed = stack.pop();\n          html.push('</' + closed.type + '>');\n        }\n        \n        let result = html.join('')\n          .replace(/!\\[(.*?)\\]\\((.*?)\\)/g, '<img src=\"$2\" alt=\"$1\">')\n          .replace(/\\*\\*(.+?)\\*\\*/g, '<strong>$1</strong>')\n          .replace(/__(.+?)__/g, '<strong>$1</strong>')\n          .replace(/\\*(.+?)\\*/g, '<em>$1</em>')\n          .replace(/_(.+?)_/g, '<em>$1</em>')\n          .replace(/`(.+?)`/g, '<code>$1</code>')\n          .replace(/\\[(.+?)\\]\\((.+?)\\)/g, '<a href=\"$2\" target=\"_blank\">$1</a>');\n        \n        result = result\n          .replace(/<br><ul>/g, '<ul>')\n          .replace(/<br><ol>/g, '<ol>')\n          .replace(/</ul><br>/g, '</ul>')\n          .replace(/</ol><br>/g, '</ol>');\n        \n        return result;\n      }\n\n      document.body.addEventListener('mouseover', function(e) {\n        if (e.target.classList.contains('editor-note')) {\n          const note = e.target.dataset.note;\n          if (note) {\n            tooltip.innerHTML = parseNoteMarkdown(note);\n            tooltip.style.display = 'block';\n            const rect = e.target.getBoundingClientRect();\n            const tooltipRect = tooltip.getBoundingClientRect();\n            const pageX = window.scrollX || window.pageXOffset;\n            const pageY = window.scrollY || window.pageYOffset;\n            const maxLeft = pageX + window.innerWidth - tooltipRect.width - 10;\n            const minLeft = pageX + 10;\n\n            let left = rect.left + pageX;\n            if (left > maxLeft) left = maxLeft;\n            if (left < minLeft) left = minLeft;\n\n            let top = rect.bottom + pageY + 6;\n            const maxTop = pageY + window.innerHeight - tooltipRect.height - 10;\n            if (top > maxTop) {\n              top = rect.top + pageY - tooltipRect.height - 6;\n            }\n            if (top < pageY + 10) top = pageY + 10;\n\n            tooltip.style.left = left + 'px';\n            tooltip.style.top = top + 'px';\n          }\n        }\n      });\n\n      document.body.addEventListener('mouseout', function(e) {\n        if (e.target.classList.contains('editor-note')) {\n          setTimeout(() => {\n            if (!tooltip.matches(':hover')) {\n              tooltip.style.display = 'none';\n            }\n          }, 100);\n        }\n      });\n\n      tooltip.addEventListener('mouseleave', function() {\n        tooltip.style.display = 'none';\n      });\n    });\n  </script>\n</head>\n<body>\n<blockquote></blockquote><h1 style=\"text-align: center\">Белодробен абсцес и Гангрена</h1><h2>Дефиниция и терминологични разлики</h2><ul><li><strong>Белодробен абсцес:</strong> Ограничена гнойна некроза на паренхима, обградена от пиогенна капсула, която отделя огнището от здравата тъкан.</li><li><strong>Белодробна гангрена:</strong> Най-тежката форма на белодробна инфекция. Характеризира се с <strong>дифузна</strong>, прогресираща некроза без ясни граници и склонност към разпад на цели лобове. Обикновено се причинява от гнилостни анаероби.</li></ul><hr><h1 style=\"text-align: center\">Белодробен абсцес</h1><h2>Дефиниция</h2><ul><li><strong>Белодробен абсцес:</strong> Ограничена гнойна некроза на паренхима, обградена от пиогенна капсула, която отделя огнището от здравата тъкан.</li></ul><h2>Статистически данни</h2><ul><li><strong>Засегнати групи:</strong> Най-често се среща при мъже на възраст <strong>40–60 години</strong>.</li><li><strong>Пол:</strong> Съотношението Мъже:Жени е <strong>4:1</strong>, което се обяснява с по-честата злоупотреба с алкохол и тютюнопушене при мъжете.</li><li><strong>Прогноза:</strong> Консервативното лечение води до 95% успех, но при хирургична намеса смъртността може да достигне <strong>10–15%</strong>.</li></ul><h2>Класификация (Според презентацията)</h2><h3>А. Според времетраенето:</h3><ul><li><strong>Остри:</strong> До 4–6 седмици от началото.</li><li><strong>Хронични:</strong> Персистиращи над 4-6 седмици (често с оформена дебела фиброзна капсула).</li></ul><h3>Б. Според патогенетичния механизъм:</h3><ol><li><p><strong>Пневмониогенни: </strong>Възникват като директно усложнение на тежка пневмония (най-често стафилококова), при която възпалителният инфилтрат не се резорбира, а некротизира и се втечнява.</p></li><li><p><strong>Аспирационни:</strong> Най-честият път (над 80%). Дължат се на вдишване на инфектиран материал от устната кухина (при лоша зъбна хигиена) или стомашно съдържание по време на сън, алкохолно опиянение или наркоза.</p><br></li><li><p><strong>Посттравматични:</strong> Развиват се след директно нараняване на гърдите (проникващи рани), при които се инфектира събран в белия дроб хематом или се внасят микроби отвън.</p><br></li><li><p><strong>Обтурационни:</strong> Причиняват се от запушване на бронх от чуждо тяло или тумор. Задържането на секрети зад препятствието води до т.нар. параканкрозен абсцес.</p><br></li><li><p><strong>Хематогенни:</strong> Микробите достигат белия дроб чрез кръвта от далечно гнойно огнище в тялото (остеомиелит, сепсис).</p><br></li><li><p><strong>Лимфогенни:</strong> Инфекцията се прехвърля по лимфните пътища от съседни органи (например от инфекция под диафрагмата).</p><br></li><li><p><strong>Тромбоемболични:</strong> Специфичен вид хематогенен път, при който септичен ембол се откъсва от вена или от сърцето, засяда в белодробен съд и предизвиква нагнояване на мястото (инфектиран инфаркт).</p></li></ol><h3>В. По локализация:</h3><ul><li><p><strong>Единични (солитарни):</strong> Обикновено са резултат от аспирация или запушване на бронх (тумор).</p></li><li><p><strong>Множествени: </strong>Характерни са за хематогенно разпространение (сепсис) или тежка стафилококова пневмония. </p></li><li><p><strong>Едностранни: </strong>Процесът е ограничен само в десния или само в левия бял дроб (често при аспирация).</p></li><li><p><strong>Двустранни:</strong> Гнойни огнища има и в двата дроба. Това е сериозен белег за разнасяне на инфекцията по кръвен път или масивна аспирация.</p></li><li><p><strong>Централни:</strong> Разположени са близо до хилуса и големите бронхи. По-лесно се дренират (изкашлят) през бронхиалното дърво.</p></li><li><p><strong>Периферни:</strong> Намират се близо до повърхността на белия дроб (под плеврата). Имат риск от пробив в плевралната кухина и развитие на пиоторакс.</p></li><li><p><strong>Със засягане на сегмент, лоб или цял белодробен дял</strong>.</p><br></li></ul><h2>Етиология (Микробиология)</h2><ul><li><strong>Анаеробна флора (60-65%): </strong>Тези бактерии нормално обитават устната кухина и предизвикват гнилостна некроза при аспирация (особено при лоша зъбна хигиена).</li><li><strong>Staphylococcus aureus:</strong> Силно агресивен причинител. Често води до множество малки абсцеси, особено след вирусни инфекции (грип) или при сепсис.</li><li><strong>Streptococcus (beta hemolytic group A): </strong>Предизвиква тежко възпаление с бързо образуване на гной.</li><li><strong>Klebsiella pneumoniae</strong>: Характерна за пациенти с диабет или алкохолизъм. Води до масивна некроза и образуване на кухини с гъста, вискозна гной.</li><li><strong>Pseudomonas aeruginosa: </strong>Чест причинител при пациенти на апаратна вентилация или със силно отслабен имунитет. Трудна за лечение поради висока резистентност.</li><li><strong>Actinomyces israelii:</strong> Предизвиква актиномикоза, което протича хронично и често образува фистули към повърхността на гръдния кош.</li><li><strong>Legionella: </strong>Предизвиква тежка пневмония, която може да некротизира до абсцес.</li><li><strong>Haemophilus influenzae:</strong> По-чест причинител при деца и пациенти с хроничен бронхит (ХОББ).</li><li><strong>Гъбични инфекции (Blastomycosis, histoplasmosis, coccidiomycosis):</strong> Обикновено причиняват хронични абсцеси с продължително протичане, често имитиращи туберкулоза или рак.</li></ul><h2>Фактори и патогенетични механизми на развитие</h2><h3>А. Локални фактори:</h3><ul><li><strong>Остър неспецифичен инфилтрат:</strong> Начална фаза на бактериална агресия.</li><li><strong>Бронхиална обструкция:</strong> Нарушен клирънс и задържане на инфектиран секрет.</li><li><strong>Локална исхемия:</strong> Компрометирана перфузия, улесняваща тъканния разпад.</li></ul><h3>Б. Общи фактори:</h3><ul><li><strong>Понижена имунологична резистентност.</strong></li><li><strong>Понижена тъканна реактивност:</strong> Невъзможност за ограничаване на процеса (водещ фактор при гангрена).</li></ul><h2>Рискови фактори</h2><ul><li><strong>Нарушено съзнание и <u>аспирация</u>:</strong> Водещ механизъм за инокулация на патогенна флора. Включва хроничен алкохолизъм, наркомании, епилепсия, състояния под обща анестезия (наркоза), инсулти и тежки черепно-мозъчни травми, които потискат кашличния и гълтателния рефлекс.</li><li><strong>Лоша устна хигиена:</strong> Наличието на кариеси, гингивити и пиорея служи като основен ендогенен резервоар за агресивна анаеробна микрофлора.</li><li><strong>Езофагеална патология:</strong> Заболявания като ГЕРБ, ахалазия и дивертикули на хранопровода, които механично улесняват аспирацията на стомашно и езофагеално съдържание.</li><li><strong>Бронхиална обструкция:</strong> Механични пречки като чужди тела или бронхиален карцином, които нарушават мукоцилиарния клирънс и водят до задържане на секрети и вторична инфекция (параканкрозен абсцес).</li><li><strong>Системни метаболитни и имунни нарушения:</strong> Захарен диабет, имуносупресивна терапия (кортикостероиди, химиотерапия), системни неоплазии и общо изтощение (недохранване).</li></ul><h2>Патоморфологични и патологоанатомични промени</h2><p>Патоморфологията на белодробния абсцес се определя от механизма на заразяване и динамиката на възпалителния процес, преминаващ от инфилтрация към некроза и фиброза.</p><ul><li><strong>Локализация и разпределение:</strong></li><ul><li><strong>Аспирационен механизъм:</strong> Най-често се засягат зоните, които са гравитационно зависими при легнало положение – задните сегменти на горния лоб на десния бял дроб (19-26%) и VI сегмент (сегмент на Fowler) на долния лоб (42-59%).</li><li><strong>Хематогенен/Септичен път:</strong> Характеризира се с множествена, често двустранна локализация (септични емболи).</li><li><strong>Обтурационен път:</strong> Локализацията зависи изцяло от мястото на първичната находка (карцином или чуждо тяло).</li></ul><li><strong>Динамика на тъканните изменения:</strong></li><ul><li><strong>Ексудативна фаза:</strong> Масивна левкоцитарна инфилтрация и изпълване на алвеолите с мътен, а впоследствие гноен ексудат. Наблюдава се некроза на капилярните стени и алвеоларните прегради.</li><li><strong>Паренхимни нарушения:</strong> Развитие на ателектаза в засегнатия участък, придружена от фибринозно-възпалителни изменения.</li><li><strong>Съдови промени:</strong> В зоната на възпалението настъпва стаза, тромбоза на малките съдове и интрапаренхимни кръвоизливи.</li></ul><li><strong>Формиране на абсцесната кухина:</strong></li><ul><li><strong>Некроза и деструкция:</strong> Пълно втечняване на белодробния паренхим и оформяне на кухина, изпълнена с детрит и гной.</li><li><strong>Хронифициране:</strong> При персистиране на процеса около некротичното огнище се формира плътна фиброзна капсула (пиогенна мембрана), която ограничава абсцеса от здравия паренхим.</li></ul></ul><h2>Клинично протичане и симптоматика</h2><p>Клиничната картина на белодробния абсцес е динамична и се развива в три последователни фази, тясно свързани с морфологичните промени в паренхима.</p><h4>I Фаза: Пневмонична</h4><p>Характеризира се с бурна и тежка клинична картина, наподобяваща крупозна пневмония. Продължава средно до 2 седмици преди формирането на кухина.</p><ul><li><strong>Общи симптоми:</strong> Висок фебрилитет, втрисане, обща отпадналост (адинамичен синдром) и безапетитие.</li><li><strong>Респираторни симптоми:</strong> Дразнеща кашлица, диспнея и бодежи/болки в гръдния кош.</li><li><strong>Обективна находка:</strong> Болезненост при перкусия и палпация в засегнатата област, придружена от кожна хиперестезия. Дишането е отслабено.</li><li><strong>Рентгенова находка:</strong> Визуализира се плътен инфилтрат без кухина.</li></ul><h4>II Фаза: На абсцедиране</h4><p>Процесът придобива характер на инфекция, която не се повлиява от стандартното антибиотично лечение.</p><ul><li><strong>Клинични белези:</strong> Фебрилитет със септичен характер (големи денонощни колебания) и нарастваща интоксикация.</li><li><strong>Промени в статуса:</strong> Увеличаване на кашлицата, нощни изпотявания и загуба на тегло.</li><li><strong>Физикална находка:</strong> Перкуторно притъпление и тахикардия.</li></ul><h4>III Фаза: На дренаж в бронх</h4><p>Настъпва при пробив на гнойното огнище в прилежащ бронх.</p><ul><li><strong>Водещ симптом (Vomic):</strong> Обилна експекторация на гной „с пълна уста“ (пурулентна секреция). Често секретът е със зловонна, гнилостна миризма (типично за анаеробна флора).</li><li><strong>Динамика:</strong> Възможно е краткотрайно субективно подобрение след изпразването на кухината. Оплакванията често протичат на тласъци, в зависимост от ефективността на бронхиалния дренаж.</li><li><strong>Рискове:</strong> Възможна е хемофтиза (кръвохрачене) поради деструкция на кръвоносни съдове в стената на абсцеса.</li></ul><h2>Фактори, водещи до хронифициране (в 4.7 – 12.1% от случаите)</h2><p>Преходът от остър в хроничен абсцес (персистиране над 6 седмици) се обуславя от механични и биологични пречки пред самоочистването на кухината:</p><ul><li><strong>Наличие на секвестър:</strong> Парчета мъртва тъкан в кухината, които поддържат инфекцията и не могат да бъдат изкашляни.</li><li><strong>Бронхиална обструкция:</strong> Запушване на дрениращия бронх, което пречи на евакуацията на гнойта.</li><li><strong>Епителизация на кухината:</strong> Покриването на вътрешната стена на абсцеса с епител пречи на нейното зарастване и свиване.</li><li><strong>Положително налягане:</strong> Вентилен механизъм в бронха, който поддържа кухината раздута.</li><li><strong>Плеврални сраствания:</strong> Фиксират белия дроб към гръдната стена и не позволяват на кухината да колабира.</li><li><strong>Перифокални промени:</strong> Наличие на пневмосклероза и тромбоемболизъм в околния паренхим, които нарушават храненето на тъканта и оздравителния процес.</li></ul><h2>Развитие и усложнения</h2><p>Еволюцията на абсцеса може да доведе до критични състояния:</p><ul><li><strong>Пробив в бронх:</strong> Води до вомик, но при лоша проходимост може да причини асфиксия или разсейване на инфекцията в други лобове.</li><li><strong>Пробив към плевралната кухина:</strong> Формиране на <strong>бронхо-плеврална фистула</strong>.</li><li><strong>Плеврален емпием:</strong> Гнойно възпаление на плеврата вследствие на пробив.</li><li><strong>Гангрена:</strong> Прогресиране на ограничения абсцес в дифузна, неограничена некроза на паренхима.</li></ul><h4>3. Лабораторни изследвания</h4><p>Параклиничните показатели отразяват тежестта на системния възпалителен отговор:</p><ul><li><strong>Пълна кръвна картина (ПКК):</strong> </li><ul><li>Изразена <strong>левкоцитоза</strong> с олевяване (увеличени неутрофили).</li><li><strong>Анемия</strong> (хипохромна), характерна за хроничните гнойни процеси.</li></ul><li><strong>Биохимия:</strong> <strong>Хипоалбуминемия</strong> поради общото изтощение и загубата на белтък чрез гнойната секреция.</li><li><strong>Микробиология:</strong> Посявка от храчка или бронхоалвеоларен лаваж за изолиране на анаероби или смесена флора. Важно за определяне на антибиотичната чувствителност.</li><li><strong>Плеврален пунктат (при излив):</strong> Изследването показва преобладаване на неутрофилни левкоцити, което е белег за гноен процес.</li></ul><h2>Инструментални диагностични изследвания</h2><p>Образните и ендоскопските методи са критични за потвърждаване на диагнозата и прецизиране на локализацията:</p><ul><li><strong><span class=\"editor-note\" data-note=\"![Image](https://files.coursebook.lol/%D0%9F%D0%B0%D0%B8%D1%81%D0%B8%D0%B9/2026-03-20/text-editor-images/2026/03/1774031886860-image.png &quot;width=100%&quot;)\" id=\"note-1774031890409-3\">Рентгенография </span>(Обзорна):</strong> Златният стандарт. </li><ul><li>В начален стадий се вижда масивен, нехомогенен инфилтрат. </li><li>След пробив в бронх се визуализира <strong>кухина с хоризонтално ниво на течност</strong>.</li></ul><li><strong><span class=\"editor-note\" data-note=\"![Image](https://files.coursebook.lol/%D0%9F%D0%B0%D0%B8%D1%81%D0%B8%D0%B9/2026-03-20/text-editor-images/2026/03/1774031846732-image.png &quot;width=100%&quot;) ![Image](https://files.coursebook.lol/%D0%9F%D0%B0%D0%B8%D1%81%D0%B8%D0%B9/2026-03-20/text-editor-images/2026/03/1774031865635-image.png &quot;width=100%&quot;)\" id=\"note-1774031848354-2\">Компютърна томография</span>:</strong> КТ е по-чувствителен метод за ранно откриване на малки кухини, секвестри и плеврални усложнения. Помага за разграничаване на абсцес от емпием.</li><li><strong>Бронхоскопия:</strong> Изключително важна за:</li><ul><li>Изключване на бронхиална обструкция (карцином или чуждо тяло).</li><li>Вземане на чиста проба за микробиологично изследване (бронхоалвеоларен лаваж).</li><li>Терапевтичен дренаж на гнойта.</li></ul><li><strong>Ехоскопия (Ултразвук):</strong> Използва се основно при периферни абсцеси за оценка на плевралния излив и насочване на пункция (торакоцентеза).</li></ul><h2>Диференциална диагноза</h2><p>Белодробният абсцес често наподобява други заболявания, протичащи с разпад на тъканта:</p><ul><li><strong>Периферен белодробен карцином с разпад (5-10%):</strong> Най-важната диференциална диагноза. Стената на раковата кухина обикновено е дебела, неравна и назъбена отвътре, а клиничното протичане е по-бавно.</li><li><strong>Туберкулозна каверна:</strong> Характеризира се с горнодялова локализация, наличие на огнищни сенки наоколо и липса на остро септично начало. Изследването на храчка за БК (бацили на Кох) е решаващо.</li><li><strong>Супурирала (нагноила) ехинококова киста:</strong> Кистата има много правилна, кръгла форма преди нагнояването. След пробив в бронх може да се види типичният образ на \"плаваща мембрана\".</li><li><strong>Супурирали бронхиектазии:</strong> Характерна е дългогодишна анамнеза с обилна сутрешна експекторация. Рентгеново се виждат множество малки кухини (тип \"пчелна пита\"), а не една голяма абсцесна кухина.</li></ul><h2>Лечение и терапевтична стратегия</h2><p>Лечението на белодробния абсцес е продължително (често 4–8 седмици) и изисква комбиниран подход: консервативни методи, инструментален дренаж и, в крайни случаи, хирургична намеса.</p><h4>А. Етиологично антибиотично лечение</h4><p>Изборът на антибиотик е съобразен с високата честота на анаеробна и смесена флора:</p><ul><li><strong>Penicillin:</strong> Исторически златен стандарт, но днес често се комбинира поради резистентност.</li><li><strong>Clindamycin:</strong> Високо ефективен срещу анаероби; често се счита за първа линия при аспирационни абсцеси.</li><li><strong>Бета-лактами с инхибитори:</strong> Широкоспектърни комбинации като <em>Ampicillin + Sulbactam</em>, <em>Amoxicillin + Clavulanate</em> и <em>Piperacillin + Tazobactam</em>.</li><li><strong>Карбапенеми (Imipenem):</strong> Резервни антибиотици за тежки инфекции с мултирезистентна анаеробна и грам-отрицателна флора.</li></ul><h4>Б. Дренажни методи и механично почистване</h4><p>Осигуряването на евакуация на гнойта е критично за оздравяването:</p><ul><li><strong><span class=\"editor-note\" data-note=\"![Image](https://external-content.duckduckgo.com/iu/?u=https%3A%2F%2Fi.pinimg.com%2Foriginals%2Fcd%2F51%2F38%2Fcd5138bf74f4aee2fb19ff63d8439d79.jpg&amp;f=1&amp;nofb=1&amp;ipt=3560672fc5cde32467e1504c5a7bab8772fa837e61ebf3d53db489962232ca1a &quot;width=100%&quot;)\" id=\"note-1774031274738-0\">Постурален дренаж</span>:</strong> Поставяне на пациента в специфично положение (зависимо от локализацията), което улеснява гравитационното оттичане на гнойта към бронхите за изкашляне.</li><li><strong>Бронхоскопия с лаваж:</strong> Директно аспириране на секрети и промиване на бронхиалното дърво.</li><li><strong>Трансбронхиален дренаж:</strong> Въвеждане на катетър през бронха директно в кухината.</li><li><strong>Перкутанен дренаж (по Моналди):</strong> Пункция през гръдната стена и поставяне на дренаж директно в абсцесната кухина (при периферни абсцеси, които не се дренират добре през бронхите).</li></ul><h4>В. Адювантна терапия</h4><ul><li><strong>Кислородотерапия:</strong> За корекция на хипоксемията при масивни инфилтрати.</li><li><strong>Барокамера (Хипербарна оксигенация):</strong> Повишава парциалното налягане на кислорода, което е пагубно за анаеробните бактерии и подобрява тъканната регенерация.</li></ul><h3>Г. Оперативно (хирургично) лечение</h3><p>Хирургичната намеса се налага при около <strong>5 – 10%</strong> от пациентите, когато консервативната терапия е изчерпана или са налице специфични деструктивни усложнения.</p><h4>Индикации за оперативно лечение</h4><p><strong>А. При остри абсцеси и гангрена:</strong></p><ul><li><strong>Терапевтична резистентност:</strong> Липса на клинично подобрение от комбинираното антибиотично и локално лечение, съпроводено с влошаване на общото състояние до 10-15-ия ден.</li><li><strong>Хеморагични усложнения:</strong> Обилно или рецидивиращо кървене от некротичното огнище.</li></ul><p><strong>Б. При хронични абсцеси:</strong></p><ul><li><strong>Абсолютни показания:</strong></li><ul><li>Хроничен абсцес в стадий на ремисия.</li><li>Обосновано съмнение за абсцедирал карцином.</li><li>Персистираща остатъчна кухина с епизоди на рецидивиращо кървене.</li><li>Супурирал (нагноил) белодробен инфаркт.</li></ul><li><strong>Относителни показания:</strong></li><ul><li>Неусложнени остатъчни кухини.</li><li>Остатъчни паренхимни изменения с клинична активност (пневмосклероза и вторични бронхиектазии).</li></ul></ul><h4>Противопоказания за операция</h4><p>Оперативният риск се счита за неприемлив при:</p><ul><li><strong>Обширност на процеса:</strong> Двустранни абсцеси с ангажиране на повече от един лоб от едната страна (липса на достатъчен функционален резерв).</li><li><strong>Системна органна недостатъчност:</strong> Тежка дихателна и сърдечно-съдова недостатъчност.</li><li><strong>Вторични дегенеративни промени:</strong> Амилоидоза на вътрешните органи (бъбреци, черен дроб) вследствие на хроничното гнойно възпаление.</li></ul><h4>Възможни следоперативни усложнения</h4><p>Хирургията при белодробна деструкция носи висок риск от инфекциозни и технически усложнения:</p><ul><li><strong>Инсуфициенция на бронхиалния чукан:</strong> Недостатъчност на шева на бронха, водеща до изтичане на въздух и инфекция.</li><li><strong>Емпием.</strong></li><li><strong>Масивна хемофтиза.</strong></li><li><strong>Пио-пневмоторакс:</strong> Наличие на гной и въздух в плевралното пространство.</li><li><strong>Гангрена:</strong> Прогресия на деструктивния процес в оставащия паренхим.</li></ul><hr><h1 style=\"text-align: center\">Гангрена на белия дроб</h1><p>Белодробната гангрена представлява най-тежката форма на инфекциозна деструкция, характеризираща се с масивна, разлята некроза на паренхима. </p><h2>Етиопатогенеза и причини за развитие</h2><p>За разлика от абсцеса, при гангрената липсва защитна бариера, което се дължи на:</p><ul><li><strong>Високо вирулентна микробна флора:</strong> Предимно анаеробни и гнилостни бактерии, които отделят мощни тъканни токсини.</li><li><strong>Снижена реактивност на организма:</strong> Силно компрометиран имунитет, при който тялото не успява да ограничи процеса (липса на демаркация).</li><li><strong>Съдови нарушения:</strong> Масивна <strong>тромбоза на интрапулмоналните съдове</strong>, която води до пълно прекъсване на кръвоснабдяването и исхемичен разпад на цели дялове.</li></ul><h2>Локализация и патоанатомия</h2><ul><li><strong>Локализация:</strong></li><ol><li><strong>Десен горен лоб (60-70%):</strong> Най-честото място на развитие поради анатомичните особености на десния главен бронх (по-стръмен от левия).</li><li><strong>Ляв горен лоб.</strong></li></ol><li><strong><span class=\"editor-note\" data-note=\"![Image](https://files.coursebook.lol/%D0%9F%D0%B0%D0%B8%D1%81%D0%B8%D0%B9/2026-03-20/text-editor-images/2026/03/1774031770889-image.png &quot;width=100%&quot;)\" id=\"note-1774031773447-1\">Патоанатомични особености</span>:</strong> Процесът протича като <strong>ликвификационна некроза</strong> (втечняване на тъканта). Характерно е отсъствието на ясна демаркационна линия (пиогенна капсула), което позволява на некрозата да се разпространява дифузно. Често се развива като терминално усложнение на тежка лобарна пневмония.</li></ul><h2>Диагностика и Образни изследвания</h2><p>При образните изследвания (Рентгенография и КТ) се наблюдава:</p><ul><li>Масивно, нехомогенно засенчване на цял лоб или бял дроб.</li><li>Наличие на множество малки, сливащи се просветлявания (кухини) с неправилна форма.</li><li>Липса на добре оформено ниво на течност, характерно за абсцеса, поради дифузния характер на разпада.</li></ul><h2>Комплексно лечение</h2><p>Лечението е агресивно и често изисква комбиниране на интензивна терапия и хирургия:</p><ul><li><strong>Специфична антибиотична терапия:</strong> Прилагане на мощни широкоспектърни комбинации. В тежки случаи се практикува <strong>канюлиране на a. pulmonalis</strong> за директно вливане на медикаменти в белодробното кръвообращение.</li><li><strong>Дренажни процедури:</strong></li><ul><li><strong>Плеврален дренаж:</strong> При пробив и развитие на пио-пневмоторакс.</li><li><strong>Трансбронхиален дренаж:</strong> За евакуация на некротичните маси през бронхиалното дърво.</li></ul><li><strong>Хирургично лечение:</strong> <strong>Белодробна резекция</strong> (лобектомия или пневмонектомия) е често единственият начин за спасяване на живота, като се отстранява изцяло некротизиралата и инфектирана тъкан.</li></ul><br><p><br></p><p><br></p><p><br></p><p><br></p><p><br></p><p><br></p><p><br></p><p><br></p><br><br><style></p><p>    body { </p><p>      font-family: \"Open Sans\", Arial, sans-serif; </p><p>      max-width: 1200px; </p><p>      margin: 2rem auto; </p><p>      padding: 0 1rem; </p><p>      line-height: 1.6; </p><p>      color: #1f2937; </p><p>    }</p><p>    h1 { </p><p>      font-weight: 600; </p><p>      font-size: 1.5em;</p><p>      margin-top: 1.5em;</p><p>      margin-bottom: 0.5em;</p><p>      color: #3a5a40;</p><p>      border-bottom: 2px dashed #a3b18a;</p><p>      padding-bottom: 5px;</p><p>    }</p><p>    p { </p><p>      margin: 0.7em 0 1.5em 0; </p><p>      white-space: pre-wrap;</p><p>    }</p><p>    @media (max-width: 768px) {</p><p>      body { font-size: 16px; }</p><p>      h1 { font-size: 1.3em; }</p><p>    }</p><p>  </style>\n<script src=\"https://cdn.jsdelivr.net/npm/katex@0.16.4/dist/katex.min.js\"></script>\n<script src=\"https://cdn.jsdelivr.net/npm/katex@0.16.4/dist/contrib/auto-render.min.js\"></script>\n<script>\nrenderMathInElement(document.body, {\n  delimiters: [\n    {left: '$$', right: '$$', display: true},\n    {left: '$', right: '$', display: false},\n    {left: '\\\\[', right: '\\\\]', display: true},\n    {left: '\\\\(', right: '\\\\)', display: false}\n  ],\n  throwOnError: false\n});\n</script>\n</body>\n</html>","files/Хирургически болести/Гръдна хирургия/4-msg-Ехинококоза на белия дроб.html":"<!DOCTYPE html>\n<html lang=\"bg\">\n<head>\n  <meta charset=\"UTF-8\">\n  <meta name=\"viewport\" content=\"width=device-width, initial-scale=1.0\">\n  <title>1</title>\n  <link rel=\"stylesheet\" href=\"https://cdn.jsdelivr.net/npm/katex@0.16.4/dist/katex.min.css\">\n  <style>\n    body { \n      font-family: \"Open Sans\", Arial, sans-serif; \n      max-width: 1550px; \n      margin: 0.5rem auto; \n      padding: 0 1rem; \n      line-height: 1.6; \n      color: #1f2937; \n    }\n    h1, h2, h3, h4 { \n      font-weight: 600; \n      margin-top: 0.7em;\n      margin-bottom: 0;\n      color: #588157;\n    }\n    h1 { font-size: 1.65em; }\n    h2 { font-size: 1.3em; }\n    h3 { font-size: 1.1em; margin-bottom: 0; }\n    h4 { font-size: 1.05em; margin-bottom: 0; }\n    h1 + h2, h1 + h3, h1 + h4, h2 + h3, h2 + h4, h3 + h4 { margin-top: 0.1em; }\n    p { \n      margin: 0.3em 0; \n      white-space: pre-wrap;\n    }\n    hr {\n      margin: 0.45em 0 0.2em;\n    }\n    hr + h1,\n    hr + h2,\n    hr + h3,\n    hr + h4 {\n      margin-top: 0.2em;\n    }\n    hr + p,\n    hr + ul,\n    hr + ol,\n    hr + blockquote,\n    hr + pre,\n    hr + table {\n      margin-top: 0.08em;\n    }\n    p + ul, p + ol { margin-top: 0.2em; }\n    h1 + p, h2 + p, h3 + p, h4 + p,\n    h1 + ul, h2 + ul, h3 + ul, h4 + ul,\n    h1 + ol, h2 + ol, h3 + ol, h4 + ol { \n      margin-top: 0; \n    }\n    ul, ol { \n      margin: 0.2em 0; \n      padding-left: 1.5em; \n      list-style-position: outside;\n    }\n    li { margin: 0.2em 0; }\n    li p {\n      margin: 0;\n      padding: 0;\n      display: inline;\n    }\n    li > ul, li > ol {\n      margin: 0.15em 0 0 0;\n      padding-left: 1.5em;\n    }\n    ul ul, ul ol, ol ul, ol ol {\n      margin-top: 0.1em;\n      padding-left: 1.5em;\n    }\n    ul ul { list-style-type: circle; }\n    ul ul ul { list-style-type: square; }\n    strong { font-weight: 600; }\n    em { font-style: italic; }\n    code { \n      background: rgba(218, 215, 205, 0.3); \n      padding: 2px 6px; \n      border-radius: 3px; \n      font-family: \"Courier New\", monospace; \n      font-size: 0.9em; \n    }\n    pre {\n      background: rgba(255, 255, 255, 0.5);\n      padding: 12px;\n      border-radius: 4px;\n      overflow-x: auto;\n      margin: 0.5em 0;\n      font-family: \"Courier New\", monospace;\n    }\n    pre code {\n      background: none;\n      padding: 0;\n    }\n    blockquote {\n      border-left: 3px solid #588157;\n      padding-left: 1em;\n      margin: 0.5em 0;\n      font-style: italic;\n      color: #166534;\n    }\n    table { \n      border-collapse: collapse; \n      margin: 0.75em 0; \n      width: 100%; \n      table-layout: auto;\n    }\n    th, td { \n      border: 1px solid rgba(2, 2, 2, 0.2);\n      padding: 6px 10px; \n      text-align: left; \n      vertical-align: top;\n      height: 24px;\n      line-height: 1.2;\n    }\n    thead th { \n      background: rgba(88, 129, 87, 0.13); \n      font-weight: 600; \n    }\n    tbody tr:nth-child(odd) { \n      background: rgba(88, 129, 87, 0.06); \n    }\n    /* Image alignment rules for exported content and md-viewer */\n    img[data-align=\"left\"] {\n      display: block;\n      margin: 8px auto 8px 0;\n    }\n    img[data-align=\"center\"] {\n      display: block;\n      margin: 8px auto;\n    }\n    img[data-align=\"right\"] {\n      display: block;\n      margin: 8px 0 8px auto;\n    }\n    .audio-link-inline {\n      display: inline-flex;\n      align-items: center;\n      gap: 8px;\n      margin: 0.2em 0;\n      max-width: 100%;\n      vertical-align: middle;\n    }\n    .audio-link-icon {\n      width: 28px;\n      height: 28px;\n      border: 1px solid #588157;\n      border-radius: 999px;\n      background: #f0f7f0;\n      color: #2f5d50;\n      cursor: pointer;\n      font-size: 14px;\n      line-height: 1;\n      display: inline-flex;\n      align-items: center;\n      justify-content: center;\n      flex: 0 0 auto;\n    }\n    .audio-link-inline audio {\n      position: absolute;\n      width: 1px;\n      height: 1px;\n      opacity: 0;\n      overflow: hidden;\n      pointer-events: none;\n    }\n    .audio-link-icon img {\n      width: 14px;\n      height: 14px;\n      object-fit: contain;\n      pointer-events: none;\n    }\n    a {\n      color: inherit; /* Changed to inherit */\n      text-decoration: underline;\n    }\n    a:hover {\n      color: #74b673;\n    }\n    /* Keep <p> tags inside list items on same line (as they appear in editor) */\n    li p {\n      margin: 0 !important;\n      padding: 0 !important;\n      display: inline !important;\n    }\n    /* Prevent nested list paragraph issues */\n    li > ul,\n    li > ol {\n      margin: 0.15em 0 0 0;\n      padding-left: 1.5em;\n    }\n    /* Ensure list structure is clean */\n    ul ul, ul ol,\n    ol ul, ol ol {\n      margin-top: 0.1em;\n      padding-left: 1.5em;\n    }\n    @media (max-width: 768px) {\n      body {\n        margin: 0.5rem 0;\n        padding: 0 0.5rem;\n        font-size: 16px;\n      }\n      h1 { font-size: 1.65em; }\n      h2 { font-size: 1.3em; }\n      h3 { font-size: 1.1em; }\n      p { margin: 0.3em 0; }\n      ul, ol { padding-left: 1.5em; }\n      li { margin: 0.2em 0; }\n      table { font-size: 0.9em; }\n      th, td { padding: 6px 10px; }\n    }\n    .editor-note {\n      text-decoration: underline dotted #a3b18a;\n      text-decoration-thickness: 2px;\n      text-underline-offset: 2px;\n      text-decoration-skip-ink: none;\n      cursor: help;\n      position: relative;\n    }\n    .note-tooltip {\n      display: none;\n      position: absolute;\n      background-color: #f0f7f0;\n      color: #1f2937;\n      border: 1px solid #588157;\n      border-radius: 4px;\n      padding: 8px 12px;\n      width: fit-content;\n      max-width: min(700px, calc(100vw - 20px));\n      max-height: calc(100vh - 20px);\n      overflow: auto;\n      box-sizing: border-box;\n      box-shadow: 0 2px 8px rgba(0,0,0,0.2);\n      z-index: 10000;\n      font-size: 0.9em;\n      line-height: 1.4;\n      word-wrap: break-word;\n    }\n    .note-tooltip ul, .note-tooltip ol {\n      margin: 0 !important;\n      padding-left: 20px !important;\n    }\n    .note-tooltip li {\n      margin: 0 0 0.1em 0 !important;\n      padding: 0 !important;\n      line-height: 1.2 !important;\n    }\n    .note-tooltip li:last-child {\n      margin-bottom: 0 !important;\n    }\n    .note-tooltip .note-table-scroll {\n      overflow-x: auto;\n      margin: 0.3em 0;\n    }\n    .note-tooltip table {\n      border-collapse: collapse;\n      width: max-content;\n      max-width: 100%;\n      min-width: 220px;\n      background: #ffffff;\n    }\n    .note-tooltip th,\n    .note-tooltip td {\n      border: 1px solid rgba(88, 129, 87, 0.35);\n      padding: 4px 8px;\n      text-align: left;\n      vertical-align: top;\n      line-height: 1.3;\n      white-space: nowrap;\n    }\n    .note-tooltip thead th {\n      background: rgba(88, 129, 87, 0.12);\n      font-weight: 600;\n    }\n  </style>\n  <script>\n    document.addEventListener('DOMContentLoaded', function() {\n      const tooltip = document.createElement('div');\n      tooltip.className = 'note-tooltip';\n      document.body.appendChild(tooltip);\n\n      function parseNoteMarkdown(text) {\n        if (!text) return '';\n        \n        const splitTableCells = function(line) {\n          return String(line || '')\n            .trim()\n            .replace(/^\\|/, '')\n            .replace(/\\|$/, '')\n            .split('|')\n            .map(function(cell) { return cell.trim(); });\n        };\n\n        const isTableSeparatorLine = function(line) {\n          const cells = splitTableCells(line);\n          return cells.length > 0 && cells.every(function(cell) {\n            return /^:?-{3,}:?$/.test(cell);\n          });\n        };\n\n        const getTableAlignment = function(cell) {\n          if (/^:-{3,}:$/.test(cell)) return 'center';\n          if (/^-{3,}:$/.test(cell)) return 'right';\n          if (/^:-{3,}$/.test(cell)) return 'left';\n          return '';\n        };\n\n        let lines = text.split('\\n');\n        let html = [];\n        let stack = [];\n        \n        for (let i = 0; i < lines.length; i++) {\n          let line = lines[i];\n          \n          let indentMatch = line.match(/^(\\s*)/);\n          let indent = indentMatch ? indentMatch[1].length : 0;\n          let content = line.trim();\n\n          const nextLine = i + 1 < lines.length ? lines[i + 1].trim() : '';\n          const maybeTableHeader = content.includes('|') && splitTableCells(content).length >= 2;\n          const maybeTableSeparator = nextLine.includes('|') && isTableSeparatorLine(nextLine);\n\n          if (maybeTableHeader && maybeTableSeparator) {\n            while (stack.length > 0) {\n              let closed = stack.pop();\n              html.push('</' + closed.type + '>');\n            }\n\n            const headerCells = splitTableCells(content);\n            const alignCells = splitTableCells(nextLine);\n\n            html.push('<div class=\"note-table-scroll\"><table><thead><tr>');\n            headerCells.forEach(function(cell, idx) {\n              const align = getTableAlignment(alignCells[idx] || '');\n              const alignAttr = align ? ' style=\"text-align:' + align + ';\"' : '';\n              html.push('<th' + alignAttr + '>' + cell + '</th>');\n            });\n            html.push('</tr></thead><tbody>');\n\n            i += 2;\n            while (i < lines.length) {\n              const rowLine = lines[i].trim();\n              if (!rowLine || !rowLine.includes('|')) break;\n              if (isTableSeparatorLine(rowLine)) {\n                i++;\n                continue;\n              }\n\n              const rowCells = splitTableCells(rowLine);\n              if (rowCells.length === 0) {\n                i++;\n                continue;\n              }\n\n              html.push('<tr>');\n              rowCells.forEach(function(cell, idx) {\n                const align = getTableAlignment(alignCells[idx] || '');\n                const alignAttr = align ? ' style=\"text-align:' + align + ';\"' : '';\n                html.push('<td' + alignAttr + '>' + cell + '</td>');\n              });\n              html.push('</tr>');\n              i++;\n            }\n\n            html.push('</tbody></table></div>');\n            i--;\n            continue;\n          }\n          \n          let isUl = /^[-*]\\s+(.+)/.test(content);\n          let isOl = /^\\d+\\.\\s+(.+)/.test(content);\n          \n          if (isUl || isOl) {\n            let listType = isUl ? 'ul' : 'ol';\n            let match = isUl ? content.match(/^[-*]\\s+(.+)/) : content.match(/^\\d+\\.\\s+(.+)/);\n            let itemText = match[1];\n            \n            if (stack.length === 0) {\n              stack.push({ type: listType, indent: indent });\n              html.push('<' + listType + '>');\n            } else {\n              let last = stack[stack.length - 1];\n              \n              if (indent > last.indent) {\n                stack.push({ type: listType, indent: indent });\n                html.push('<' + listType + '>');\n              } else if (indent < last.indent) {\n                while (stack.length > 0 && stack[stack.length - 1].indent > indent) {\n                  let closed = stack.pop();\n                  html.push('</' + closed.type + '>');\n                }\n                if (stack.length === 0 || stack[stack.length - 1].indent !== indent) {\n                   stack.push({ type: listType, indent: indent });\n                   html.push('<' + listType + '>');\n                } else if (stack[stack.length - 1].type !== listType) {\n                   let closed = stack.pop();\n                   html.push('</' + closed.type + '>');\n                   stack.push({ type: listType, indent: indent });\n                   html.push('<' + listType + '>');\n                }\n              } else {\n                if (last.type !== listType) {\n                  let closed = stack.pop();\n                  html.push('</' + closed.type + '>');\n                  stack.push({ type: listType, indent: indent });\n                  html.push('<' + listType + '>');\n                }\n              }\n            }\n            html.push('<li>' + itemText + '</li>');\n          } else {\n            if (content !== '') {\n               while (stack.length > 0) {\n                 let closed = stack.pop();\n                 html.push('</' + closed.type + '>');\n               }\n            }\n            if (/^#{1,4}\\s+/.test(content)) {\n              const headingMatch = content.match(/^(#{1,4})\\s+(.+)$/);\n              if (headingMatch) {\n                const level = headingMatch[1].length;\n                html.push('<h' + level + '>' + headingMatch[2] + '</h' + level + '>');\n              }\n            } else if (content) {\n              html.push(content + '<br>');\n            } else {\n              html.push('<br>');\n            }\n          }\n        }\n        \n        while (stack.length > 0) {\n          let closed = stack.pop();\n          html.push('</' + closed.type + '>');\n        }\n        \n        let result = html.join('')\n          .replace(/!\\[(.*?)\\]\\((.*?)\\)/g, '<img src=\"$2\" alt=\"$1\">')\n          .replace(/\\*\\*(.+?)\\*\\*/g, '<strong>$1</strong>')\n          .replace(/__(.+?)__/g, '<strong>$1</strong>')\n          .replace(/\\*(.+?)\\*/g, '<em>$1</em>')\n          .replace(/_(.+?)_/g, '<em>$1</em>')\n          .replace(/`(.+?)`/g, '<code>$1</code>')\n          .replace(/\\[(.+?)\\]\\((.+?)\\)/g, '<a href=\"$2\" target=\"_blank\">$1</a>');\n        \n        result = result\n          .replace(/<br><ul>/g, '<ul>')\n          .replace(/<br><ol>/g, '<ol>')\n          .replace(/</ul><br>/g, '</ul>')\n          .replace(/</ol><br>/g, '</ol>');\n        \n        return result;\n      }\n\n      document.body.addEventListener('mouseover', function(e) {\n        if (e.target.classList.contains('editor-note')) {\n          const note = e.target.dataset.note;\n          if (note) {\n            tooltip.innerHTML = parseNoteMarkdown(note);\n            tooltip.style.display = 'block';\n            const rect = e.target.getBoundingClientRect();\n            const tooltipRect = tooltip.getBoundingClientRect();\n            const pageX = window.scrollX || window.pageXOffset;\n            const pageY = window.scrollY || window.pageYOffset;\n            const maxLeft = pageX + window.innerWidth - tooltipRect.width - 10;\n            const minLeft = pageX + 10;\n\n            let left = rect.left + pageX;\n            if (left > maxLeft) left = maxLeft;\n            if (left < minLeft) left = minLeft;\n\n            let top = rect.bottom + pageY + 6;\n            const maxTop = pageY + window.innerHeight - tooltipRect.height - 10;\n            if (top > maxTop) {\n              top = rect.top + pageY - tooltipRect.height - 6;\n            }\n            if (top < pageY + 10) top = pageY + 10;\n\n            tooltip.style.left = left + 'px';\n            tooltip.style.top = top + 'px';\n          }\n        }\n      });\n\n      document.body.addEventListener('mouseout', function(e) {\n        if (e.target.classList.contains('editor-note')) {\n          setTimeout(() => {\n            if (!tooltip.matches(':hover')) {\n              tooltip.style.display = 'none';\n            }\n          }, 100);\n        }\n      });\n\n      tooltip.addEventListener('mouseleave', function() {\n        tooltip.style.display = 'none';\n      });\n    });\n  </script>\n</head>\n<body>\n<blockquote></blockquote><h1 style=\"text-align: center\">Белодробна ехинококоза (Echinococcosis Pulmonis)</h1><h2>Същност</h2><p>Белодробната ехинококоза е тежка <strong>антропозооноза</strong> (заболяване, общо за хората и животните), която се развива в резултат на инфектиране с ларвната форма на кучешката тения. Характеризира се с образуването на ехинококови кисти в белодробния паренхим, които могат да нарастват бавно в продължение на десетилетия.</p><hr><h2>Причинители</h2><p>Заболяването се причинява от различни видове цестоди (плоски червеи) от род <em>Echinococcus</em>:</p><ul><li><strong>Echinococcus granulosus</strong> (най-често срещаният, наричан още <em>Echinococcus unilocularis</em>).</li><li><strong>Alveococcus multilocularis</strong> (причинител на алвеоларна ехинококоза).</li><li><strong>Echinococcus vogeli</strong>.</li><li><strong>Echinococcus oligarthus</strong>.</li></ul><hr><h2>Заболеваемост</h2><p>Статистическите данни показват значимо присъствие на заболяването в България:</p><ul><li><strong>Обща заболеваемост:</strong> Около <strong>6,95 на 100 000</strong> души.</li><li><strong>Локализация:</strong> Белият дроб е второто най-често ангажирано място след черния дроб, като заема между <strong>20% и 35%</strong> от всички случаи на ехинококоза.</li></ul><hr><h2>Разпространение</h2><p>Заболяването е тясно свързано с климатичните условия и развитото животновъдство.</p><ul><li><strong>Ендемични райони:</strong></li><ul><li><strong>Балкански полуостров:</strong> България, Гърция, Турция.</li><li><strong>Средиземноморски басейн:</strong> Италия, Испания.</li><li><strong>Южна Америка:</strong> Уругвай, Аржентина, Чили.</li><li><strong>Други:</strong> Австралия, Нова Зеландия, Северна Африка, Близкия изток и Средна Азия.</li></ul><li><strong>Рискови фактори:</strong> Сух и топъл климат, интензивно скотовъдство и ниски нива на санитарно-хигиенна култура в селските райони.</li></ul><hr><h2>Етиология и морфология на зародиша (Онкосфера)</h2><p>Преди навлизането в организма, паразитът съществува под формата на яйце (онкосфера), притежаващо следните характеристики:</p><ul><li><strong>Структура:</strong></li><ol><li>Хитинова обвивка</li><li>Герминативна обвивка</li><li>Зародиш (Онкосфера)</li></ol></ul><p><img src=\"https://files.coursebook.lol/%D0%9F%D0%B0%D0%B8%D1%81%D0%B8%D0%B9/2026-04-01/text-editor-images/2026/04/1775062753400-image.png\" alt=\"https://files.coursebook.lol/%D0%9F%D0%B0%D0%B8%D1%81%D0%B8%D0%B9/2026-04-01/text-editor-images/2026/04/1775062753400-image.png\" data-original-src=\"https://files.coursebook.lol/%D0%9F%D0%B0%D0%B8%D1%81%D0%B8%D0%B9/2026-04-01/text-editor-images/2026/04/1775062753400-image.png\" data-width=\"80\" data-align=\"left\" style=\"width: 402.4px; max-width: 100%; height: auto; display: block; float: none; margin: 8px auto 8px 0px\" data-broken-cleanup-bound=\"1\"></p><ul><li><strong>Устойчивост:</strong></li><ul><li>Във вода или на слънце: <strong>12 дни</strong>.</li><li>При 0℃ преживяват до <strong>116 дни</strong>.</li></ul></ul><hr><h2><span class=\"editor-note\" data-note=\"![Image](https://external-content.duckduckgo.com/iu/?u=https%3A%2F%2Fcdn.lecturio.com%2Fassets%2FEchinococcus-granulosus-Life-Cycle-Echinococcosis.jpg&amp;f=1&amp;nofb=1&amp;ipt=f2cd952e499387d20d93e12e17e12981cc443bda7cf65f38ee4a283b27a42a8f &quot;width=100%&quot;)\" id=\"note-1775062824608-1\">Биологичен цикъл</span></h2><p>Белодробната ехинококоза е паразитно заболяване, причинено от ларвната форма на тенията <strong>Echinococcus granulosus</strong>. Човекът се включва в цикъла като \"случаен\" и \"терминален\" междинен гостоприемник.</p><ul><li><strong>Краен (дефинитивен) гостоприемник:</strong> Месоядни животни (куче, вълк, чакал). Половозрелите форми (3–6 мм) живеят в техните тънки черва.</li><li><strong>Междинен гостоприемник:</strong> Над 60 вида бозайници (едър и дребен рогат добитък, свине, елени, маймуни) и <strong>Човек</strong>.</li></ul><h4>Пътища на заразяване</h4><ul><li><p><strong>Стомашно-чревен (Перорален) – основен:</strong></p></li><ul><li><p>Консумация на немити плодове/зеленчуци и замърсена вода.</p></li><li><p>Директен контакт (галене) с опаразитени кучета.</p></li></ul><li><strong>Дихателен път (Аерогенен):</strong> Вдишване на прах, съдържащ ехинококови яйца.</li></ul><ul><li><p><strong>Директен път:</strong> Попадане на яйца директно в ранева повърхност.</p></li></ul><h3>Миграция в организма (Пътят до Белия дроб)</h3><p>След поглъщане, обвивката на яйцето се смила от стомашните и жлъчните ензими, освобождавайки хексакантния ембрион.</p><p><strong>А. Хематогенен път</strong></p><ul><li><strong>I Филът (Черен дроб): </strong>Ларвата прониква в чревната стена и чрез Vena Portae попада в черния дроб. Тук се спират <strong>75–80% </strong>от онкосферите.</li><li><strong>II Филтър (Бял дроб): </strong>Оцелелите ларви преминават през чернодробните вени -&gt; Vena Cava Inferior -&gt; дясно сърце -&gt; Белодробна артерия. Тук се фиксират <strong>20–35%</strong> от случаите.</li><li><strong>III Филтър (Системно разпространение):</strong> Ако преминат белодробните капиляри, попадат в лявото сърце и аортата (мозък, бъбреци, кости).</li></ul><p><strong>Б. Алтернативни пътища (Заобикаляне на черния дроб)</strong></p><ul><li><strong>Лимфогенен:</strong> <p>Ларвата прониква в лимфните съдове на червата -&gt; <strong>ductus thoracicus</strong> -&gt; v. subclavia -&gt; дясно сърце -&gt; бял дроб.</p></li><li><strong>Порто-кавални анастомози: </strong><p>Преминаване през венозни връзки, заобикалящи порталната система.</p></li><li><strong>Трансдиафрагмален:</strong> <p>Директна миграция от черния дроб към белия дроб при тясно съседство през диафрагмата.</p></li></ul><hr><h2>Структура на ехинококовата киста (Личинков стадий)</h2><p>Веднъж фиксирана в паренхима, онкосферата образува киста, състояща се от:</p><ul><li><strong>Кутикулярна (хитинова) мембрана:</strong> Предпазва паразита.</li><li><strong>Герминативна мембрана:</strong> Вътрешен слой, който произвежда зародишните елементи.</li><li><strong>Ехинококова течност:</strong> Прозрачна, под високо налягане.</li><li><strong>Елементи на „пясъка“:</strong> Зародишеви мехури, сколекси и дъщерни клетки.</li><li><strong>Важно:</strong> Растежът в белия дроб е по-бърз (<strong>1–3 см/година</strong>) поради еластичността на тъканта. Средната продължителност на живот на кистата е <strong>10–20 години</strong>.</li></ul><hr><h2>Особености на белодробната ехинококоза</h2><ul><li><strong>Честота:</strong> 20 – 35% от всички случаи на ехинококоза.</li><li><strong>Брой кисти:</strong> Най-често се среща <strong>солитарна</strong> (единична) киста.</li><ul><li>Множествена ехинококоза: 10 – 40%.</li><li>Двустранна локализация: 10 – 20%.</li></ul><li><strong>Съчетана (полиорганна) ехинококоза:</strong> 6,6 – 21% (най-често с черния дроб).</li><li><strong>Локализация:</strong> По-често в <strong>десния бял дроб</strong>, периферно разположение и в <strong>долните сегменти</strong>.</li></ul><hr><h2>Клиника</h2><p>Развитието на заболяването преминава през четири основни стадия:</p><h4>I. Латентен стадий</h4><ul><li><strong>Период:</strong> От инвазията на онкосферата до първите клинични прояви.</li><li><strong>Характеристика:</strong> Продължителен (години), особено при централно разположени кисти.</li><li><strong>Диагностика:</strong> Обикновено се открива случайно при рентгеново изследване (10-25% от болните).</li></ul><h4>II. Стадий на начални клинични прояви</h4><p>Симптомите са неспецифични и наподобяват лека респираторна инфекция:</p><ul><li>Суха кашлица или с оскъдна експекторация.</li><li>Гръдна болка (от чувство за тежест до невралгична болка).</li><li>Субфебрилитет, обща отпадналост и изпотяване.</li><li><strong>Алергични прояви:</strong> Уртикариален обрив.</li><li>Дискретна хемофтиза (кръвохрачене).</li></ul><h4>III. Стадий на изявени клинични прояви</h4><p>Кистата е достигнала големи размери и притиска околните структури:</p><ul><li>Постоянна кашлица и задух (прогресираща диспнея).</li><li>Усилване на болката и кръвохраченето.</li><li><strong>Хемодинамични разстройства:</strong> Дължат се на изместване на медиастинума.</li><li><strong>Локален статус:</strong>&nbsp;</li><ul><li>Асиметрия на гръдния кош (при деца и слаби хора).</li><li>Изгладени междуребрия.</li><li>Изоставане на съответната гръдна половина при дишане.</li><li>Перкуторно притъпление и отслабено дишане.&nbsp;</li><li>При възпаление на околния паренхим се чуват крепитации и дребни влажни хрипове.</li></ul></ul><h3>IV. Стадий на усложненията</h3><p>Това е най-опасният етап, свързан с разрушаване целостта на кистата:</p><h4>А. Пробив към бронхиалното дърво (20 – 40%)</h4><p>По-често се наблюдава при централно разположените кисти.</p><ul><li><strong>Отхрачване на:</strong> </li><ul><li><strong>С</strong><strong>олено-горчива течност</strong>. Може да бъде фудроянтно (масивно) с риск от асфиксия.</li><li><strong>Находка в храчката:</strong> Изкашляне на хитинови мембрани и дъщерни кисти.</li><li><strong>Зловонна гной (при абсцедиране)</strong></li><li><strong>Кръвохрак.</strong></li></ul><li><strong>Усложнение:</strong> Може да доведе до опаразитяване на двата бели дроба или вторичен белодробен абсцес (при нагнояване).</li><li><strong>Клинична картина на белодробен абсцес</strong>.</li></ul><h4>Б. Пробив към плевралната кухина (2 – 5%)</h4><p>Води до драматична клинична картина:</p><ul><li>Хидатиден хидропневмоторакс.</li><li>Емпием или пиопневмоторакс (ако кистата е била нагноила).</li><li>Риск от анафилактичен шок.</li></ul><h4>В. Други усложнения</h4><ul><li><strong>Пробив към перикарда:</strong> Рядко, води до тампонада и смърт.</li><li><strong>Нагнояване на ехинококовата киста:</strong> Клиника на недрениран белодробен абсцес.</li><li><strong>Дегенеративни промени в кистата:</strong> Самоизлекуване чрез колоидна дегенерация и калцифициране на кистата.</li></ul><h3>Специфични форми</h3><ul><li><strong>Множествена ехинококоза:</strong>&nbsp;Едностранна или двустранна с по-кратък латентен период, тежка клиника и чести усложнения.</li><li><strong>Съчетана ехинококоза:</strong> Клиничната картина се владее от най-голямата или усложнена киста (напр. в черния дроб или мозъка).</li></ul><p><img src=\"https://files.coursebook.lol/%D0%9F%D0%B0%D0%B8%D1%81%D0%B8%D0%B9/2026-04-01/text-editor-images/2026/04/1775063434830-image.png\" alt=\"image\" data-original-src=\"https://files.coursebook.lol/%D0%9F%D0%B0%D0%B8%D1%81%D0%B8%D0%B9/2026-04-01/text-editor-images/2026/04/1775063434830-image.png\" data-width=\"100\" data-align=\"center\" style=\"width: 907px; max-width: 100%; height: auto; display: block; float: none; margin: 8px auto\" data-broken-cleanup-bound=\"1\"></p><hr><h2>Диагноза</h2><p>Диагнозата се поставя чрез комплексен подход, обединяващ клиничната картина, високоспециализирани образни изследвания и специфични серологични тестове.</p><h3>1. Образна диагностика</h3><p>Образните методи са водещи за локализирането и определянето на състоянието на кистата (жива, нагноила или пукната).</p><h4>А. <span class=\"editor-note\" data-note=\"![Image](https://files.coursebook.lol/%D0%9F%D0%B0%D0%B8%D1%81%D0%B8%D0%B9/2026-04-01/text-editor-images/2026/04/1775063772729-image.png &quot;width=100%&quot;)\" id=\"note-1775063782084-3\">Рентгеново изследване (Ro)</span></h4><p>Това е основният метод, приложим при кисти с размер над 15–20 мм. Може да се наблюдават следните рентгенови белези:</p><ul><li><strong><span class=\"editor-note\" data-note=\"![Image](https://files.coursebook.lol/%D0%9F%D0%B0%D0%B8%D1%81%D0%B8%D0%B9/2026-04-01/text-editor-images/2026/04/1775063595965-image.png &quot;width=100%&quot;)\" id=\"note-1775063598160-2\">Граничен симптом</span>:</strong> Интензивността на сянката на кистата е по-малка в сравнение със сенките на съседните ребра.</li><li><strong>Симптом на Неменов (\"Дишане на кистата\"):</strong> Промяна във формата на кистата (от кръгла в елипсовидна) при дълбоко вдишване и издишване поради еластичността на стените ѝ.</li><li><strong>Симптом на Дилон (Краеви симптом):</strong> Характерни очертания при периферно разположени кисти.</li><li><strong>Симптом на Щерн (\"Удвояване на контура\"):</strong> Визуализира се поради разликата в плътността между перикистата (обвивката от гостоприемника) и хитиновата мембрана.</li><li><strong>Симптом на Schlanger (\"На хващащата тумора ръка\"):</strong> Специфично обхващане на формацията от съседни структури.</li><li><strong>Симптом на \"Въздушната шапка\" (на полумесеца):</strong> Рано отлепване на хитиновата мембрана, при което между нея и перикистата прониква въздух.</li><li><strong><span class=\"editor-note\" data-note=\"![Image](https://files.coursebook.lol/%D0%9F%D0%B0%D0%B8%D1%81%D0%B8%D0%B9/2026-04-01/text-editor-images/2026/04/1775063893044-image.png &quot;width=100%&quot;)\n![Image](https://files.coursebook.lol/%D0%9F%D0%B0%D0%B8%D1%81%D0%B8%D0%B9/2026-04-01/text-editor-images/2026/04/1775063884140-image.png &quot;width=100%&quot;)\" id=\"note-1775063894681-4\">Симптом на \"Водната лилия\" </span>:</strong> Наблюдава се след пробив на кистата в бронх. Хитиновата мембрана колабира и \"плува\" върху остатъчната течност в кухината.</li><li><strong>Симптом на петрификация:</strong> Вижда се при калцифициране на кистата след смърт на паразита (рядко при белодробна локализация).</li></ul><p><br></p><h4>Б. КАТ (Компютърна аксиална томография) и ЯМР</h4><p>Прилагат се основно при трудности в диференциалната диагноза. КАТ позволява прецизна оценка на плътността на течността и откриване на малки дъщерни кисти.</p><h4>В. Други образни методи</h4><ul><li><strong>Ултрасонография (Ехография):</strong> Полезна при периферни кисти и за изключване на съпътстваща чернодробна ехинококоза.</li><li><strong>Перфузионна сцинтиграфия:</strong> За оценка на функционалния капацитет на белия дроб около кистата.</li></ul><h3>2. Лабораторни и имунологични изследвания</h3><p>Серологичните тестове помагат за потвърждаване на паразитарния произход, но имат по-ниска чувствителност при белодробна локализация (60-65%) в сравнение с чернодробната (80-90%).</p><ul><li><strong>Класически тестове:</strong></li><ul><li><strong>Казони (Casoni):</strong> Интрадермален тест (кожна проба). Понастоящем се използва по-рядко поради риск от алергични реакции.</li><li><strong>Вайнберг (Weinberg):</strong> Реакция за свързване на комплемента (РСК).</li></ul><li><strong>Съвременни серологични реакции:</strong></li><ul><li><strong>ELISA:</strong> Счита се за един от най-чувствителните и специфични методи.</li><li><strong>Реакция индиректна хемаглутинация (РИХА)</strong>.<strong></strong></li><li><strong>Реакция пасивна хемаглутинация (РПХА)</strong>.</li><li><strong>Реакция индиректна имунофлуоресценция (РИФ)</strong>.</li><li><strong>Латекс аглутинация</strong> и <strong>Бентонит флуоресценция</strong>.</li></ul></ul><hr><h2>Диференциална диагноза</h2><p>Поради своята рентгенологична характеристика (кръгла сянка или кухина с нива), ехинококовата киста трябва да бъде отграничена от широк кръг заболявания:</p><ul><li><strong>Белодробни тумори:</strong></li><ul><li><strong>Доброкачествени тумори:</strong> Често имат подобна правилна форма, но по-голяма плътност.</li><li><strong>Периферен белодробен карцином:</strong> Обикновено е с по-неравни контури и по-бърза динамика.</li><li><strong>Белодробни метастази:</strong> Често са множество.</li></ul><li><strong>Възпалителни и специфични заболявания:</strong></li><ul><li><strong>Белодробен абсцес:</strong> Протича с тежка клинична картина (температура, гнойни храчки) и дебели стени на кухината.</li><li><strong>Белодробна туберкулоза:</strong> Търсят се специфични огнища и БК в храчката.</li></ul><li><strong>Плеврални и съдови процеси:</strong></li><ul><li><strong>Ограничени изливи и емпиеми:</strong> Променят се при смяна на положението на тялото.</li><li><strong>Аневризми на аортата:</strong> Изискват КТ с контраст или ангиография за изключване.</li></ul><li><strong>Други локализации:</strong></li><ul><li><strong>Тумори на медиастинума.</strong></li><li><strong>Целомни кисти (на перикарда).</strong></li><li><strong>Релаксация на диафрагмата:</strong> Може да имитира формация в долните белодробни отдели.</li></ul></ul><hr><h2>Профилактика</h2><p>Профилактиката е ключова за ограничаване на разпространението на ехинококозата и включва лични и обществени мерки:</p><h4>Лична профилактика:</h4><ul><li><strong>Хигиена:</strong> Строго спазване на елементарни хигиенни норми (миене на ръцете след контакт с животни).</li><li><strong>Хранене:</strong> Консумиране на нискорастящи плодове (ягоди) и зеленчуци (марули, лук) само след <strong>обилно и добро измиване</strong> под течаща вода.</li><li><strong>Контакт с животни:</strong> Ограничаване на прекия контакт с кучета с неясен здравен статус.</li></ul><h4>Обществена и ветеринарна профилактика:</h4><ul><li><strong>Контрол над скитащите кучета:</strong> Намаляване на популацията и редовен надзор.</li><li><strong>Дехелминтоза:</strong> Редовно обезпаразитяване на домашните и овчарските кучета.</li><li><strong>Ветеринарен контрол:</strong> Недопускане на кучета до кланици и забрана за храненето им със сурови вътрешности (черен и бял дроб) на заклани животни.</li><li><strong>Здравна просвета:</strong> Информиране на населението в ендемичните райони за пътищата на заразяване.</li></ul><hr><h2>Лечение на белодробна ехинококоза</h2><p>Лечението на белодробната ехинококоза е комплексно, като водещо е хирургичното отстраняване на паразита, често съчетано с постоперативна химиотерапия.</p><h3>1. Хирургическо лечение</h3><p>Основните цели на операцията са отстраняване на паразита, антисептична обработка и ликвидиране на остатъчната кухина.</p><h4>А. Методи за отстраняване на паразита</h4><ul><li><strong>Открита ехинококектомия:</strong> Извършва се пункция и евакуация на съдържимото, инстилиране на сколициден разтвор (за убиване на зародишите) и след това отстраняване на кистата.</li><li><strong>Закрита ехинококектомия:</strong> Фиброзната капсула се надрязва внимателно и кистата се изважда <strong>интактна</strong>, без да се разкъсва.</li></ul><h4>Б. <span class=\"editor-note\" data-note=\"![Image](https://files.coursebook.lol/%D0%9F%D0%B0%D0%B8%D1%81%D0%B8%D0%B9/2026-04-01/text-editor-images/2026/04/1775063950836-image.png &quot;width=100%&quot;)\" id=\"note-1775064076861-6\">Третиране на остатъчната фиброзна кухина</span></h4><p>След отстраняване на кистата кухината се обработва със сколицидни разтвори (<strong>хипертоничен NaCl, спирт или йод</strong>). Дрениращите бронхи се зашиват, а кухината се ликвидира чрез:</p><ul><li><strong>Капитонаж:</strong> Зашиване на стените на кухината една към друга.</li><li><strong>Метод на Delbet:</strong> Налагане на кесийни шевове (спираловидно или шахматно).</li><li><strong>Метод на Вишневски:</strong> Изрязване на фиброзните ръбове и превръщане на дъното на кухината в повърхност на белия дроб (при периферни кисти).</li><li><strong>Лепилни или шевно-лепилни методи.</strong></li></ul><h3>В. Резекционни методи</h3><p>Прилагат се при тежки поражения на белодробния паренхим:</p><ul><li><strong>Атипична резекция:</strong> При периферни кисти без загуба на паренхим.</li><li><strong>Анатомична резекция (<span class=\"editor-note\" data-note=\"![Image](https://files.coursebook.lol/%D0%9F%D0%B0%D0%B8%D1%81%D0%B8%D0%B9/2026-04-01/text-editor-images/2026/04/1775064051915-image.png &quot;width=100%&quot;)\" id=\"note-1775064062249-5\">Лобектомия</span>):</strong> При изконсумиран или необратими тежки промени в околния паренхим.</li><li><strong>Операция на Перец-Фонтана:</strong> Ехинококектомия заедно с фиброзната капсула (рядко, при малки перифенни кисти).</li></ul><h3>2. Хирургично поведение при специфични форми</h3><ul><li><strong>Усложнени форми (<span class=\"editor-note\" data-note=\"![Image](https://files.coursebook.lol/%D0%9F%D0%B0%D0%B8%D1%81%D0%B8%D0%B9/2026-04-01/text-editor-images/2026/04/1775064104036-image.png &quot;width=100%&quot;)\" id=\"note-1775064105109-7\">пробив в плеврата</span>):</strong> <em> </em></li><ul><li><i>Ранна операция</i>: Ехинококектомия, третиране на остатъчната кухина и сколицидна обработка на плеврата.</li><li><em>Късна операция:</em>&nbsp;Ехинококектмоя, третиране на остатъчната кухина и се налага&nbsp;<strong>декортикация с плевректомия</strong>.</li></ul><li><strong><span class=\"editor-note\" data-note=\"![Image](https://files.coursebook.lol/%D0%9F%D0%B0%D0%B8%D1%81%D0%B8%D0%B9/2026-04-01/text-editor-images/2026/04/1775064115543-image.png &quot;width=100%&quot;)\" id=\"note-1775064116931-8\">Двустранна локализация</span>:</strong>&nbsp;</li><ul><li><strong>E</strong><strong>дноетапна:&nbsp;</strong>чрез стернотомия или двустранна торакотомия.</li><li><strong>Dвуетапна</strong><strong>:</strong> първо се оперира по-голямата или усложнена киста, а след 1-3 месеца – другата.</li></ul><li><strong>Съчетана ехинококоза (бял дроб + коремни органи):</strong>&nbsp;</li><ul><li><strong>Едноетапна</strong>: тораколапаротомия или торакофренотомия</li><li><strong>Двуетапна</strong>: <p>последователни операции на торакотомия и лапаротомия.</p></li></ul></ul><h3>3. Консервативно лечение (Химиотерапия)</h3><p><strong>Показания:</strong> </p><ul><li>Малки единични кисти (до 3-4 см).</li><li>Неоперабилни болни.</li><li>Полиорганна авансирала ехинококоза.</li><li>Предоперативно при усложнени форми.</li><li>В следоперативния период при усложнени форми или съмнения за опаразитяване. </li></ul><p><strong>Препарати:</strong></p><ul><li><strong>Vermox:</strong> 50 – 60 mg/kg дневно за 6 месеца.</li><li><strong>Zentel (Albendazole):</strong> 10 mg/kg дневно за 4 месеца (с интервали от 15 дни).</li></ul><h3>4. Диспансеризация и Прогноза</h3><ul><li><strong>Диспансеризация:</strong>&nbsp;<strong>!Задължителна! </strong>за период от <strong>10 – 15 години</strong>.</li><li><strong>Проследяване:</strong> Периодични серологични изследвания и рентгенов контрол.</li><li><strong>Рецидиви:</strong> Наблюдават се при около <strong>6%</strong> от случаите.</li></ul><hr><h2>Билиобронхиални фистули</h2><p>Това е едно от най-тежките усложнения при съчетана ехинококоза на черния и белия дроб.</p><ul><li><strong>Механизъм:</strong> Развива се при пробив на чернодробна ехинококова киста през диафрагмата директно в бронхиалното дърво.</li><li><strong>Патогномоничен симптом (Билиоптиза):</strong> Изкашляне на <strong>жлъчка</strong> (жълто-зеленикави, горчиви храчки).</li><li><strong>Диагностика:</strong></li><ul><li><strong>КТ:</strong> Златен стандарт за доказване на фистулния ход между двата органа.</li><li><strong>Бронхоскопия:</strong> Визуализира наличие на жлъчка в бронхите.</li></ul><li><strong>Лечение:</strong> Винаги оперативно.</li><ul><li><strong>Достъп:</strong> Торакофренолапаротомия (комбиниран достъп).</li><li><strong>Цел:</strong> Ликвидиране на кистите, зашиване на фистулния канал и пластика (възстановяване) на дефекта на диафрагмата.</li></ul></ul><img src=\"https://files.coursebook.lol/%D0%9F%D0%B0%D0%B8%D1%81%D0%B8%D0%B9/2026-04-01/text-editor-images/2026/04/1775064381999-image.png\" alt=\"https://files.coursebook.lol/%D0%9F%D0%B0%D0%B8%D1%81%D0%B8%D0%B9/2026-04-01/text-editor-images/2026/04/1775064381999-image.png\" data-original-src=\"https://files.coursebook.lol/%D0%9F%D0%B0%D0%B8%D1%81%D0%B8%D0%B9/2026-04-01/text-editor-images/2026/04/1775064381999-image.png\" data-width=\"100\" data-align=\"center\" style=\"width: 968px; max-width: 100%; height: auto; display: block; float: none; margin: 8px auto\" data-broken-cleanup-bound=\"1\"><br><br><h3><br></h3><p><br></p><br><br><style></p><p>    body { </p><p>      font-family: \"Open Sans\", Arial, sans-serif; </p><p>      max-width: 1200px; </p><p>      margin: 2rem auto; </p><p>      padding: 0 1rem; </p><p>      line-height: 1.6; </p><p>      color: #1f2937; </p><p>    }</p><p>    h1 { </p><p>      font-weight: 600; </p><p>      font-size: 1.5em;</p><p>      margin-top: 1.5em;</p><p>      margin-bottom: 0.5em;</p><p>      color: #3a5a40;</p><p>      border-bottom: 2px dashed #a3b18a;</p><p>      padding-bottom: 5px;</p><p>    }</p><p>    p { </p><p>      margin: 0.7em 0 1.5em 0; </p><p>      white-space: pre-wrap;</p><p>    }</p><p>    @media (max-width: 768px) {</p><p>      body { font-size: 16px; }</p><p>      h1 { font-size: 1.3em; }</p><p>    }</p><p>  </style>\n<script src=\"https://cdn.jsdelivr.net/npm/katex@0.16.4/dist/katex.min.js\"></script>\n<script src=\"https://cdn.jsdelivr.net/npm/katex@0.16.4/dist/contrib/auto-render.min.js\"></script>\n<script>\nrenderMathInElement(document.body, {\n  delimiters: [\n    {left: '$$', right: '$$', display: true},\n    {left: '$', right: '$', display: false},\n    {left: '\\\\[', right: '\\\\]', display: true},\n    {left: '\\\\(', right: '\\\\)', display: false}\n  ],\n  throwOnError: false\n});\n</script>\n</body>\n</html>"};
